describe("subscribe - multiple listeners", () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });
  afterEach(() => {
    vi.useRealTimers();
  });

  it("multiple listeners on same subscription all get notified", async () => {
    const storage = createMemoryAdapter();
    await testBlock.initialize(storage);

    const client = createBlockClient(testBlock, storage, {
      userId: "user-1",
      pollInterval: 50,
    });

    const sub = client.subscribe("items");
    const listener1 = vi.fn();
    const listener2 = vi.fn();

    const unsub1 = sub.subscribe(listener1);
    // Second subscribe after first — should not restart polling
    const unsub2 = sub.subscribe(listener2);

    await client.call("addItem", { label: "shared" });
    await vi.advanceTimersByTimeAsync(100);

    expect(listener1).toHaveBeenCalled();
    expect(listener2).toHaveBeenCalled();

    unsub1();
    // Timer still running (listener2 active)
    listener1.mockClear();
    listener2.mockClear();

    await client.call("addItem", { label: "another" });
    await vi.advanceTimersByTimeAsync(100);

    // listener1 unsubscribed, should not receive
    expect(listener1).not.toHaveBeenCalled();
    // listener2 still active
    expect(listener2).toHaveBeenCalled();

    unsub2();
  });
});

import { describe, expect, it } from "vitest";
import {
  defineTable,
  schemaTableNames,
  schemaToSQL,
  t,
  tableToSQL,
} from "@spike-land-ai/block-sdk";

describe("Schema DSL", () => {
  describe("defineTable", () => {
    it("creates a table definition from column builders", () => {
      const table = defineTable("users", {
        id: t.string().primaryKey(),
        name: t.string(),
        age: t.number().optional(),
      });

      expect(table.name).toBe("users");
      expect(table.columns.id).toEqual({ type: "string", primary: true, optional: false });
      expect(table.columns.name).toEqual({ type: "string", primary: false, optional: false });
      expect(table.columns.age).toEqual({ type: "number", primary: false, optional: true });
    });

    it("handles enum columns", () => {
      const table = defineTable("tasks", {
        status: t.enum(["pending", "done"]),
      });
      expect(table.columns.status).toEqual({
        type: "string",
        primary: false,
        optional: false,
        enumValues: ["pending", "done"],
      });
    });

    it("handles u64 and boolean types", () => {
      const table = defineTable("events", {
        timestamp: t.u64(),
        active: t.boolean(),
      });
      expect(table.columns.timestamp!.type).toBe("u64");
      expect(table.columns.active!.type).toBe("boolean");
    });
  });

  describe("tableToSQL", () => {
    it("generates CREATE TABLE with correct types", () => {
      const table = defineTable("tasks", {
        id: t.string().primaryKey(),
        title: t.string(),
        count: t.number(),
        active: t.boolean(),
        created: t.u64(),
        notes: t.string().optional(),
      });

      const sql = tableToSQL(table);
      expect(sql).toContain("CREATE TABLE IF NOT EXISTS tasks");
      expect(sql).toContain("id TEXT PRIMARY KEY");
      expect(sql).toContain("title TEXT NOT NULL");
      expect(sql).toContain("count INTEGER NOT NULL");
      expect(sql).toContain("active INTEGER NOT NULL");
      expect(sql).toContain("created INTEGER NOT NULL");
      // Optional columns should NOT have NOT NULL
      expect(sql).toMatch(/notes TEXT(?!\s+NOT NULL)/);
    });
  });

  describe("schemaToSQL", () => {
    it("generates SQL for all tables in schema", () => {
      const schema = {
        users: defineTable("users", { id: t.string().primaryKey() }),
        tasks: defineTable("tasks", { id: t.string().primaryKey(), title: t.string() }),
      };

      const sqls = schemaToSQL(schema);
      expect(sqls).toHaveLength(2);
      expect(sqls[0]).toContain("CREATE TABLE IF NOT EXISTS users");
      expect(sqls[1]).toContain("CREATE TABLE IF NOT EXISTS tasks");
    });
  });

  describe("schemaTableNames", () => {
    it("extracts table names from schema", () => {
      const schema = {
        users: defineTable("users", { id: t.string().primaryKey() }),
        tasks: defineTable("tasks", { id: t.string().primaryKey() }),
      };

      const names = schemaTableNames(schema);
      expect(names).toEqual(["users", "tasks"]);
    });
  });

  describe("toSQLType default branch", () => {
    it("returns TEXT for unknown column type", () => {
      const table = defineTable("test", {
        col: t.string(),
      });
      // Force the type to an unknown value to hit the default branch
      (table.columns["col"] as { type: string }).type = "unknown_type";
      const sql = tableToSQL(table);
      expect(sql).toContain("col TEXT");
    });
  });

  describe("ColumnBuilder chaining", () => {
    it("primaryKey and optional are chainable and state is reflected", () => {
      const col = t.string().primaryKey();
      expect(col._def.primary).toBe(true);
      expect(col._def.optional).toBe(false);

      const col2 = t.number().optional();
      expect(col2._def.optional).toBe(true);
      expect(col2._def.primary).toBe(false);
    });

    it("enum column has enumValues in _def", () => {
      const col = t.enum(["a", "b", "c"]);
      expect(col._def.enumValues).toEqual(["a", "b", "c"]);
      expect(col._def.type).toBe("string");
    });
  });

  describe(".default()", () => {
    it("sets string default value", () => {
      const col = t.string().default("pending");
      expect(col._def.defaultValue).toBe("pending");
    });

    it("sets number default value", () => {
      const col = t.number().default(0);
      expect(col._def.defaultValue).toBe(0);
    });

    it("sets boolean default value", () => {
      const col = t.boolean().default(true);
      expect(col._def.defaultValue).toBe(true);
    });

    it("generates DEFAULT 'value' for string defaults in SQL", () => {
      const table = defineTable("tasks", {
        id: t.string().primaryKey(),
        status: t.string().default("pending"),
      });
      const sql = tableToSQL(table);
      expect(sql).toContain("status TEXT NOT NULL DEFAULT 'pending'");
    });

    it("generates DEFAULT 0 for number defaults in SQL", () => {
      const table = defineTable("counters", {
        id: t.string().primaryKey(),
        count: t.number().default(0),
      });
      const sql = tableToSQL(table);
      expect(sql).toContain("count INTEGER NOT NULL DEFAULT 0");
    });

    it("generates DEFAULT 1 for true and DEFAULT 0 for false in SQL", () => {
      const table = defineTable("flags", {
        id: t.string().primaryKey(),
        active: t.boolean().default(true),
        deleted: t.boolean().default(false),
      });
      const sql = tableToSQL(table);
      expect(sql).toContain("active INTEGER NOT NULL DEFAULT 1");
      expect(sql).toContain("deleted INTEGER NOT NULL DEFAULT 0");
    });
  });

  describe(".references()", () => {
    it("sets foreignKey on column def", () => {
      const col = t.string().references("users", "id");
      expect(col._def.foreignKey).toEqual({ table: "users", column: "id" });
    });

    it("generates REFERENCES clause in SQL", () => {
      const table = defineTable("tasks", {
        id: t.string().primaryKey(),
        user_id: t.string().references("users", "id"),
      });
      const sql = tableToSQL(table);
      expect(sql).toContain("user_id TEXT NOT NULL REFERENCES users(id)");
    });

    it("combines default and references", () => {
      const table = defineTable("tasks", {
        id: t.string().primaryKey(),
        status: t.string().default("open").references("statuses", "name"),
      });
      const sql = tableToSQL(table);
      expect(sql).toContain("status TEXT NOT NULL DEFAULT 'open' REFERENCES statuses(name)");
    });
  });

  describe("indexes", () => {
    it("defineTable accepts indexes option", () => {
      const table = defineTable(
        "tasks",
        { id: t.string().primaryKey(), user_id: t.string() },
        { indexes: [{ name: "idx_tasks_user", columns: ["user_id"] }] },
      );
      expect(table.indexes).toEqual([{ name: "idx_tasks_user", columns: ["user_id"] }]);
    });

    it("defineTable without indexes option has no indexes field", () => {
      const table = defineTable("tasks", { id: t.string().primaryKey() });
      expect(table.indexes).toBeUndefined();
    });

    it("schemaToSQL generates CREATE INDEX statements", () => {
      const schema = {
        tasks: defineTable(
          "tasks",
          { id: t.string().primaryKey(), user_id: t.string(), status: t.string() },
          { indexes: [{ name: "idx_tasks_user", columns: ["user_id"] }] },
        ),
      };
      const sqls = schemaToSQL(schema);
      expect(sqls).toHaveLength(2);
      expect(sqls[1]).toBe("CREATE INDEX IF NOT EXISTS idx_tasks_user ON tasks(user_id)");
    });

    it("schemaToSQL generates CREATE UNIQUE INDEX for unique indexes", () => {
      const schema = {
        users: defineTable(
          "users",
          { id: t.string().primaryKey(), email: t.string() },
          { indexes: [{ name: "idx_users_email", columns: ["email"], unique: true }] },
        ),
      };
      const sqls = schemaToSQL(schema);
      expect(sqls[1]).toBe("CREATE UNIQUE INDEX IF NOT EXISTS idx_users_email ON users(email)");
    });

    it("schemaToSQL generates multi-column index", () => {
      const schema = {
        tasks: defineTable(
          "tasks",
          { id: t.string().primaryKey(), user_id: t.string(), status: t.string() },
          { indexes: [{ name: "idx_tasks_user_status", columns: ["user_id", "status"] }] },
        ),
      };
      const sqls = schemaToSQL(schema);
      expect(sqls[1]).toBe(
        "CREATE INDEX IF NOT EXISTS idx_tasks_user_status ON tasks(user_id, status)",
      );
    });

    it("schemaToSQL generates multiple indexes per table", () => {
      const schema = {
        tasks: defineTable(
          "tasks",
          { id: t.string().primaryKey(), user_id: t.string(), status: t.string() },
          {
            indexes: [
              { name: "idx_tasks_user", columns: ["user_id"] },
              { name: "idx_tasks_status", columns: ["status"], unique: false },
            ],
          },
        ),
      };
      const sqls = schemaToSQL(schema);
      expect(sqls).toHaveLength(3);
      expect(sqls[1]).toContain("idx_tasks_user");
      expect(sqls[2]).toContain("idx_tasks_status");
    });
  });

  describe("combined features", () => {
    it("full table with defaults, references, and indexes", () => {
      const schema = {
        tasks: defineTable(
          "tasks",
          {
            id: t.string().primaryKey(),
            title: t.string(),
            status: t.string().default("pending"),
            user_id: t.string().references("users", "id"),
            priority: t.number().default(0),
          },
          {
            indexes: [
              { name: "idx_tasks_user", columns: ["user_id"] },
              { name: "idx_tasks_status_priority", columns: ["status", "priority"], unique: false },
            ],
          },
        ),
      };

      const sqls = schemaToSQL(schema);
      expect(sqls).toHaveLength(3);

      const createTable = sqls[0];
      expect(createTable).toContain("status TEXT NOT NULL DEFAULT 'pending'");
      expect(createTable).toContain("user_id TEXT NOT NULL REFERENCES users(id)");
      expect(createTable).toContain("priority INTEGER NOT NULL DEFAULT 0");

      expect(sqls[1]).toBe("CREATE INDEX IF NOT EXISTS idx_tasks_user ON tasks(user_id)");
      expect(sqls[2]).toBe(
        "CREATE INDEX IF NOT EXISTS idx_tasks_status_priority ON tasks(status, priority)",
      );
    });
  });
});

import { describe, expect, it, beforeEach } from "vitest";
import { sqliteAdapter } from "../../src/core/block-sdk/db/sqlite.js";
import type { StorageAdapter } from "../../src/core/block-sdk/core-logic/types-block-sdk.js";

describe("SQLite StorageAdapter", () => {
  let adapter: StorageAdapter;

  beforeEach(() => {
    adapter = sqliteAdapter(); // in-memory
  });

  describe("WAL mode", () => {
    it("should have WAL journal mode active for file-based databases", async () => {
      const os = await import("node:os");
      const path = await import("node:path");
      const fs = await import("node:fs");
      const dbPath = path.join(os.tmpdir(), `test-wal-${Date.now()}.db`);
      try {
        const fileAdapter = sqliteAdapter({ path: dbPath });
        const result = await fileAdapter.sql.execute<{ journal_mode: string }>(
          "PRAGMA journal_mode",
        );
        expect(result.rows[0]!.journal_mode).toBe("wal");
      } finally {
        // Clean up temp files
        for (const suffix of ["", "-wal", "-shm"]) {
          try {
            fs.unlinkSync(dbPath + suffix);
          } catch {}
        }
      }
    });

    it("should report memory journal mode for in-memory databases", async () => {
      const result = await adapter.sql.execute<{ journal_mode: string }>("PRAGMA journal_mode");
      expect(result.rows[0]!.journal_mode).toBe("memory");
    });
  });

  describe("KV adapter", () => {
    it("should return null for missing key", async () => {
      expect(await adapter.kv.get("missing")).toBeNull();
    });

    it("should put and get a value", async () => {
      await adapter.kv.put("key1", { hello: "world" });
      expect(await adapter.kv.get("key1")).toEqual({ hello: "world" });
    });

    it("should overwrite existing key", async () => {
      await adapter.kv.put("key1", "v1");
      await adapter.kv.put("key1", "v2");
      expect(await adapter.kv.get("key1")).toBe("v2");
    });

    it("should delete a key and return true", async () => {
      await adapter.kv.put("key1", "val");
      expect(await adapter.kv.delete("key1")).toBe(true);
      expect(await adapter.kv.get("key1")).toBeNull();
    });

    it("should return false when deleting non-existent key", async () => {
      expect(await adapter.kv.delete("nope")).toBe(false);
    });

    it("should list all keys", async () => {
      await adapter.kv.put("a:1", 1);
      await adapter.kv.put("a:2", 2);
      await adapter.kv.put("b:1", 3);
      const all = await adapter.kv.list();
      expect(all).toHaveLength(3);
    });

    it("should list keys with prefix", async () => {
      await adapter.kv.put("user:1", { name: "Alice" });
      await adapter.kv.put("user:2", { name: "Bob" });
      await adapter.kv.put("post:1", { title: "Hello" });
      const users = await adapter.kv.list("user:");
      expect(users).toHaveLength(2);
      expect(users.map((e) => e.key)).toEqual(["user:1", "user:2"]);
    });
  });

  describe("SQL adapter", () => {
    it("should execute CREATE TABLE and INSERT", async () => {
      await adapter.sql.execute("CREATE TABLE items (id INTEGER PRIMARY KEY, name TEXT NOT NULL)");
      const result = await adapter.sql.execute("INSERT INTO items (id, name) VALUES (?, ?)", [
        1,
        "foo",
      ]);
      expect(result.rowsAffected).toBe(1);
    });

    it("should execute SELECT", async () => {
      await adapter.sql.execute("CREATE TABLE items (id INTEGER PRIMARY KEY, name TEXT)");
      await adapter.sql.execute("INSERT INTO items (id, name) VALUES (?, ?)", [1, "foo"]);
      await adapter.sql.execute("INSERT INTO items (id, name) VALUES (?, ?)", [2, "bar"]);
      const result = await adapter.sql.execute<{ id: number; name: string }>("SELECT * FROM items");
      expect(result.rows).toHaveLength(2);
      expect(result.rows[0]!.name).toBe("foo");
    });

    it("should execute UPDATE", async () => {
      await adapter.sql.execute("CREATE TABLE items (id INTEGER PRIMARY KEY, name TEXT)");
      await adapter.sql.execute("INSERT INTO items (id, name) VALUES (?, ?)", [1, "foo"]);
      const result = await adapter.sql.execute("UPDATE items SET name = ? WHERE id = ?", [
        "bar",
        1,
      ]);
      expect(result.rowsAffected).toBe(1);
      const check = await adapter.sql.execute<{ name: string }>(
        "SELECT name FROM items WHERE id = ?",
        [1],
      );
      expect(check.rows[0]!.name).toBe("bar");
    });

    it("should execute DELETE", async () => {
      await adapter.sql.execute("CREATE TABLE items (id INTEGER PRIMARY KEY, name TEXT)");
      await adapter.sql.execute("INSERT INTO items (id, name) VALUES (?, ?)", [1, "foo"]);
      const result = await adapter.sql.execute("DELETE FROM items WHERE id = ?", [1]);
      expect(result.rowsAffected).toBe(1);
    });

    it("should support ORDER BY and LIMIT", async () => {
      await adapter.sql.execute("CREATE TABLE items (id INTEGER PRIMARY KEY, name TEXT)");
      await adapter.sql.execute("INSERT INTO items (id, name) VALUES (?, ?)", [1, "c"]);
      await adapter.sql.execute("INSERT INTO items (id, name) VALUES (?, ?)", [2, "a"]);
      await adapter.sql.execute("INSERT INTO items (id, name) VALUES (?, ?)", [3, "b"]);

      const result = await adapter.sql.execute<{ name: string }>(
        "SELECT name FROM items ORDER BY name ASC LIMIT 2",
      );
      expect(result.rows.map((r) => r.name)).toEqual(["a", "b"]);
    });

    it("should enforce foreign key constraints", async () => {
      await adapter.sql.execute(
        "CREATE TABLE parents (id INTEGER PRIMARY KEY, name TEXT NOT NULL)",
      );
      await adapter.sql.execute(
        "CREATE TABLE children (id INTEGER PRIMARY KEY, parent_id INTEGER NOT NULL REFERENCES parents(id))",
      );

      await expect(
        adapter.sql.execute("INSERT INTO children (id, parent_id) VALUES (?, ?)", [1, 999]),
      ).rejects.toThrow();
    });

    it("should batch queries in a transaction", async () => {
      await adapter.sql.execute("CREATE TABLE items (id INTEGER PRIMARY KEY, name TEXT)");

      const results = await adapter.sql.batch([
        { query: "INSERT INTO items (id, name) VALUES (?, ?)", params: [1, "a"] },
        { query: "INSERT INTO items (id, name) VALUES (?, ?)", params: [2, "b"] },
        { query: "SELECT * FROM items" },
      ]);

      expect(results).toHaveLength(3);
      expect(results[0]!.rowsAffected).toBe(1);
      expect(results[1]!.rowsAffected).toBe(1);
      expect(results[2]!.rows).toHaveLength(2);
    });
  });

  describe("Blob adapter", () => {
    it("should return null for missing blob", async () => {
      expect(await adapter.blobs!.get("missing")).toBeNull();
    });

    it("should put and get ArrayBuffer", async () => {
      const data = new Uint8Array([1, 2, 3, 4]).buffer;
      await adapter.blobs!.put("blob1", data as ArrayBuffer);
      const result = await adapter.blobs!.get("blob1");
      expect(result).not.toBeNull();
      expect(new Uint8Array(result!)).toEqual(new Uint8Array([1, 2, 3, 4]));
    });

    it("should put and get Uint8Array", async () => {
      const data = new Uint8Array([10, 20, 30]);
      await adapter.blobs!.put("blob2", data);
      const result = await adapter.blobs!.get("blob2");
      expect(new Uint8Array(result!)).toEqual(new Uint8Array([10, 20, 30]));
    });

    it("should delete a blob and return true", async () => {
      await adapter.blobs!.put("blob1", new Uint8Array([1]));
      expect(await adapter.blobs!.delete("blob1")).toBe(true);
      expect(await adapter.blobs!.get("blob1")).toBeNull();
    });

    it("should return false when deleting non-existent blob", async () => {
      expect(await adapter.blobs!.delete("nope")).toBe(false);
    });

    it("should list blobs with prefix", async () => {
      await adapter.blobs!.put("img:1", new Uint8Array([1]));
      await adapter.blobs!.put("img:2", new Uint8Array([2]));
      await adapter.blobs!.put("doc:1", new Uint8Array([3]));

      const imgs = await adapter.blobs!.list("img:");
      expect(imgs).toEqual(["img:1", "img:2"]);

      const all = await adapter.blobs!.list();
      expect(all).toHaveLength(3);
    });
  });
});

import { describe, expect, it } from "vitest";
import { createMemoryAdapter } from "@spike-land-ai/block-sdk/storage";

describe("createMemoryAdapter", () => {
  describe("KV", () => {
