        ["claimed", "alice", "1", "pending"],
      );
      expect(result.rowsAffected).toBe(1);

      const check = await adapter.sql.execute("SELECT * FROM tasks WHERE id = ?", ["1"]);
      expect(check.rows[0]).toEqual({ id: "1", status: "claimed", assignee: "alice" });
    });

    it("returns 0 rows affected when no match for UPDATE", async () => {
      const adapter = createMemoryAdapter();
      await adapter.sql.execute("CREATE TABLE tasks (id TEXT, status TEXT)");
      await adapter.sql.execute("INSERT INTO tasks (id, status) VALUES (?, ?)", ["1", "done"]);

      const result = await adapter.sql.execute(
        "UPDATE tasks SET status = ? WHERE id = ? AND status = ?",
        ["claimed", "1", "pending"],
      );
      expect(result.rowsAffected).toBe(0);
    });

    it("deletes rows", async () => {
      const adapter = createMemoryAdapter();
      await adapter.sql.execute("CREATE TABLE tasks (id TEXT, title TEXT)");
      await adapter.sql.execute("INSERT INTO tasks (id, title) VALUES (?, ?)", ["1", "A"]);
      await adapter.sql.execute("INSERT INTO tasks (id, title) VALUES (?, ?)", ["2", "B"]);

      const result = await adapter.sql.execute("DELETE FROM tasks WHERE id = ?", ["1"]);
      expect(result.rowsAffected).toBe(1);

      const remaining = await adapter.sql.execute("SELECT * FROM tasks");
      expect(remaining.rows).toHaveLength(1);
      expect(remaining.rows[0]).toEqual({ id: "2", title: "B" });
    });

    it("batch executes multiple queries", async () => {
      const adapter = createMemoryAdapter();
      await adapter.sql.execute("CREATE TABLE items (id TEXT, name TEXT)");

      const results = await adapter.sql.batch([
        { query: "INSERT INTO items (id, name) VALUES (?, ?)", params: ["1", "apple"] },
        { query: "INSERT INTO items (id, name) VALUES (?, ?)", params: ["2", "banana"] },
      ]);
      expect(results).toHaveLength(2);
      expect(results[0]!.rowsAffected).toBe(1);

      const all = await adapter.sql.execute("SELECT * FROM items");
      expect(all.rows).toHaveLength(2);
    });

    it("throws on unsupported SQL", async () => {
      const adapter = createMemoryAdapter();
      await expect(adapter.sql.execute("ALTER TABLE foo ADD COLUMN bar TEXT")).rejects.toThrow(
        "Unsupported SQL statement",
      );
    });

    it("drops tables", async () => {
      const adapter = createMemoryAdapter();
      await adapter.sql.execute("CREATE TABLE temp (id TEXT)");
      await adapter.sql.execute("INSERT INTO temp (id) VALUES (?)", ["1"]);
      await adapter.sql.execute("DROP TABLE IF EXISTS temp");

      // Table should be gone — re-select returns empty (new table)
      await adapter.sql.execute("CREATE TABLE temp (id TEXT)");
      const result = await adapter.sql.execute("SELECT * FROM temp");
      expect(result.rows).toHaveLength(0);
    });
  });

  describe("Blobs", () => {
    it("puts and gets ArrayBuffer", async () => {
      const adapter = createMemoryAdapter();
      const data = new TextEncoder().encode("hello").buffer;
      await adapter.blobs!.put("file1", data);
      const result = await adapter.blobs!.get("file1");
      expect(new TextDecoder().decode(result!)).toBe("hello");
    });

    it("puts Uint8Array", async () => {
      const adapter = createMemoryAdapter();
      const data = new TextEncoder().encode("world");
      await adapter.blobs!.put("file2", data);
      const result = await adapter.blobs!.get("file2");
      expect(result).not.toBeNull();
      expect(new TextDecoder().decode(result!)).toBe("world");
    });

    it("returns null for missing blobs", async () => {
      const adapter = createMemoryAdapter();
      expect(await adapter.blobs!.get("nope")).toBeNull();
    });

    it("deletes blobs", async () => {
      const adapter = createMemoryAdapter();
      await adapter.blobs!.put("f", new Uint8Array([1, 2, 3]));
      expect(await adapter.blobs!.delete("f")).toBe(true);
      expect(await adapter.blobs!.get("f")).toBeNull();
    });

    it("lists blobs with prefix", async () => {
      const adapter = createMemoryAdapter();
      await adapter.blobs!.put("img/1.png", new Uint8Array([1]));
      await adapter.blobs!.put("img/2.png", new Uint8Array([2]));
      await adapter.blobs!.put("doc/1.pdf", new Uint8Array([3]));

      const imgs = await adapter.blobs!.list("img/");
      expect(imgs.sort()).toEqual(["img/1.png", "img/2.png"]);
    });

    it("lists all blobs when no prefix", async () => {
      const adapter = createMemoryAdapter();
      await adapter.blobs!.put("a.txt", new Uint8Array([1]));
      await adapter.blobs!.put("b.txt", new Uint8Array([2]));
      const all = await adapter.blobs!.list();
      expect(all.sort()).toEqual(["a.txt", "b.txt"]);
    });

    it("puts ReadableStream", async () => {
      const adapter = createMemoryAdapter();
      const text = "stream data";
      const encoded = new TextEncoder().encode(text);
      const stream = new ReadableStream({
        start(controller) {
          controller.enqueue(encoded);
          controller.close();
        },
      });
      await adapter.blobs!.put("stream-key", stream);
      const result = await adapter.blobs!.get("stream-key");
      expect(result).not.toBeNull();
      expect(new TextDecoder().decode(result!)).toBe(text);
    });

    it("delete returns false for missing key", async () => {
      const adapter = createMemoryAdapter();
      expect(await adapter.blobs!.delete("nonexistent")).toBe(false);
    });
  });

  describe("SQL - additional coverage", () => {
    it("deletes all rows from table without WHERE clause", async () => {
      const adapter = createMemoryAdapter();
      await adapter.sql.execute("CREATE TABLE things (id TEXT)");
      await adapter.sql.execute("INSERT INTO things (id) VALUES (?)", ["1"]);
      await adapter.sql.execute("INSERT INTO things (id) VALUES (?)", ["2"]);
      await adapter.sql.execute("INSERT INTO things (id) VALUES (?)", ["3"]);

      const result = await adapter.sql.execute("DELETE FROM things");
      expect(result.rowsAffected).toBe(3);

      const remaining = await adapter.sql.execute("SELECT * FROM things");
      expect(remaining.rows).toHaveLength(0);
    });

    it("kv delete returns false for non-existent key", async () => {
      const adapter = createMemoryAdapter();
      expect(await adapter.kv.delete("ghost")).toBe(false);
    });

    it("INSERT without params inserts nulls", async () => {
      const adapter = createMemoryAdapter();
      await adapter.sql.execute("CREATE TABLE t (id TEXT, val TEXT)");
      // No params provided - columns should be null
      const result = await adapter.sql.execute("INSERT INTO t (id, val) VALUES (?, ?)");
      expect(result.rows[0]).toEqual({ id: null, val: null });
    });

    it("UPDATE SET without null params uses null fallback", async () => {
      const adapter = createMemoryAdapter();
      await adapter.sql.execute("CREATE TABLE t (id TEXT, name TEXT)");
      await adapter.sql.execute("INSERT INTO t (id, name) VALUES (?, ?)", ["1", "old"]);
      // Only provide WHERE params, not SET params - SET values become null
      await adapter.sql.execute("UPDATE t SET name = ? WHERE id = ?", [
        undefined as unknown as string,
        "1",
      ]);
      const rows = await adapter.sql.execute("SELECT * FROM t WHERE id = ?", ["1"]);
      // The SET value was undefined/null
      expect(rows.rows[0]).toBeDefined();
    });

    it("SELECT with WHERE AND multiple conditions", async () => {
      const adapter = createMemoryAdapter();
      await adapter.sql.execute("CREATE TABLE t (id TEXT, status TEXT, assignee TEXT)");
      await adapter.sql.execute("INSERT INTO t (id, status, assignee) VALUES (?, ?, ?)", [
        "1",
        "active",
        "alice",
      ]);
      await adapter.sql.execute("INSERT INTO t (id, status, assignee) VALUES (?, ?, ?)", [
        "2",
        "active",
        "bob",
      ]);
      await adapter.sql.execute("INSERT INTO t (id, status, assignee) VALUES (?, ?, ?)", [
        "3",
        "done",
        "alice",
      ]);

      const result = await adapter.sql.execute(
        "SELECT * FROM t WHERE status = ? AND assignee = ?",
        ["active", "alice"],
      );
      expect(result.rows).toHaveLength(1);
      expect(result.rows[0]).toEqual({ id: "1", status: "active", assignee: "alice" });
    });
  });
});

import { describe, expect, it } from "vitest";
import { createMemoryAdapter } from "@spike-land-ai/block-sdk";
import { taskQueue } from "@spike-land-ai/block-tasks";
import type { Task } from "@spike-land-ai/block-tasks";

describe("taskQueue block", () => {
  it("has correct name and version", () => {
    expect(taskQueue.name).toBe("task-queue");
    expect(taskQueue.version).toBe("1.0.0");
  });

  it("generates schema migration for tasks table", () => {
    expect(taskQueue.migrations).toHaveLength(1);
    expect(taskQueue.migrations[0]).toContain("CREATE TABLE IF NOT EXISTS tasks");
    expect(taskQueue.migrations[0]).toContain("id TEXT PRIMARY KEY");
    expect(taskQueue.migrations[0]).toContain("title TEXT NOT NULL");
    expect(taskQueue.migrations[0]).toContain("status TEXT NOT NULL");
  });

  it("auto-discovers all 6 tool names", () => {
    expect(taskQueue.toolNames.sort()).toEqual([
      "claim_task",
      "complete_task",
      "create_task",
      "delete_task",
      "get_task",
      "list_tasks",
    ]);
  });

  describe("procedures", () => {
    async function setup() {
      const storage = createMemoryAdapter();
      await taskQueue.initialize(storage);
      const procs = taskQueue.createProcedures(storage, "alice");
      return { storage, procs };
    }

    it("create_task creates a pending task", async () => {
      const { procs } = await setup();
      const result = await procs.createTask.handler({
        title: "Fix bug",
        description: "Fix the login bug",
      });

      expect(result.isError).toBeUndefined();
      const task = JSON.parse(result.content[0]!.text!) as Task;
      expect(task.title).toBe("Fix bug");
      expect(task.description).toBe("Fix the login bug");
      expect(task.status).toBe("pending");
      expect(task.assignee).toBe("");
      expect(task.id).toBeTruthy();
      expect(task.created).toBeGreaterThan(0);
    });

    it("list_tasks returns all tasks", async () => {
      const { procs } = await setup();
      await procs.createTask.handler({ title: "Task 1", description: "" });
      await procs.createTask.handler({ title: "Task 2", description: "" });

      const result = await procs.listTasks.handler({});
      const tasks = JSON.parse(result.content[0]!.text!) as Task[];
      expect(tasks).toHaveLength(2);
    });

    it("list_tasks filters by status", async () => {
      const { procs } = await setup();
      await procs.createTask.handler({ title: "Pending 1", description: "" });

      const createResult = await procs.createTask.handler({ title: "To Claim", description: "" });
      const task = JSON.parse(createResult.content[0]!.text!) as Task;
      await procs.claimTask.handler({ taskId: task.id });

      const pendingResult = await procs.listTasks.handler({ status: "pending" });
      const pending = JSON.parse(pendingResult.content[0]!.text!) as Task[];
      expect(pending).toHaveLength(1);
      expect(pending[0]!.title).toBe("Pending 1");

      const claimedResult = await procs.listTasks.handler({ status: "claimed" });
      const claimed = JSON.parse(claimedResult.content[0]!.text!) as Task[];
      expect(claimed).toHaveLength(1);
      expect(claimed[0]!.title).toBe("To Claim");
    });

    it("get_task returns a specific task", async () => {
      const { procs } = await setup();
      const createResult = await procs.createTask.handler({
        title: "My Task",
        description: "details",
      });
      const created = JSON.parse(createResult.content[0]!.text!) as Task;

      const getResult = await procs.getTask.handler({ taskId: created.id });
      const task = JSON.parse(getResult.content[0]!.text!) as Task;
      expect(task.title).toBe("My Task");
      expect(task.description).toBe("details");
    });

    it("get_task returns error for missing task", async () => {
      const { procs } = await setup();
      const result = await procs.getTask.handler({ taskId: "nonexistent" });
      expect(result.isError).toBe(true);
      expect(result.content[0]!.text).toContain("NOT_FOUND");
    });

    it("claim_task claims a pending task", async () => {
      const { procs } = await setup();
      const createResult = await procs.createTask.handler({ title: "Claimable", description: "" });
      const task = JSON.parse(createResult.content[0]!.text!) as Task;

      const claimResult = await procs.claimTask.handler({ taskId: task.id });
      expect(claimResult.isError).toBeUndefined();
      const data = JSON.parse(claimResult.content[0]!.text!);
      expect(data.claimed).toBe(true);
      expect(data.assignee).toBe("alice");

      // Verify the task is now claimed
      const getResult = await procs.getTask.handler({ taskId: task.id });
      const updated = JSON.parse(getResult.content[0]!.text!) as Task;
      expect(updated.status).toBe("claimed");
      expect(updated.assignee).toBe("alice");
    });

    it("claim_task fails if already claimed", async () => {
      const { procs } = await setup();
      const createResult = await procs.createTask.handler({ title: "Race", description: "" });
      const task = JSON.parse(createResult.content[0]!.text!) as Task;

      await procs.claimTask.handler({ taskId: task.id });

      // Second claim should fail
      const secondClaim = await procs.claimTask.handler({ taskId: task.id });
      expect(secondClaim.isError).toBe(true);
      expect(secondClaim.content[0]!.text).toContain("ALREADY_CLAIMED");
    });

    it("complete_task marks a claimed task as done", async () => {
      const { procs } = await setup();
      const createResult = await procs.createTask.handler({ title: "Finishable", description: "" });
      const task = JSON.parse(createResult.content[0]!.text!) as Task;

      await procs.claimTask.handler({ taskId: task.id });
      const completeResult = await procs.completeTask.handler({ taskId: task.id });
      expect(completeResult.isError).toBeUndefined();
      const data = JSON.parse(completeResult.content[0]!.text!);
      expect(data.completed).toBe(true);

      // Verify status
      const getResult = await procs.getTask.handler({ taskId: task.id });
      const updated = JSON.parse(getResult.content[0]!.text!) as Task;
      expect(updated.status).toBe("done");
    });

    it("complete_task fails if not claimed by current user", async () => {
      const { storage } = await setup();

      // Create as alice, claim as alice
      const aliceProcs = taskQueue.createProcedures(storage, "alice");
      const createResult = await aliceProcs.createTask.handler({
        title: "Alice's task",
        description: "",
      });
      const task = JSON.parse(createResult.content[0]!.text!) as Task;
      await aliceProcs.claimTask.handler({ taskId: task.id });

      // Try to complete as bob
      const bobProcs = taskQueue.createProcedures(storage, "bob");
      const result = await bobProcs.completeTask.handler({ taskId: task.id });
      expect(result.isError).toBe(true);
      expect(result.content[0]!.text).toContain("NOT_CLAIMABLE");
    });

    it("delete_task removes a task", async () => {
      const { procs } = await setup();
      const createResult = await procs.createTask.handler({ title: "Deletable", description: "" });
      const task = JSON.parse(createResult.content[0]!.text!) as Task;

      const deleteResult = await procs.deleteTask.handler({ taskId: task.id });
      expect(deleteResult.isError).toBeUndefined();
      const data = JSON.parse(deleteResult.content[0]!.text!);
      expect(data.deleted).toBe(true);

      // Verify it's gone
      const getResult = await procs.getTask.handler({ taskId: task.id });
      expect(getResult.isError).toBe(true);
    });

    it("delete_task returns error for missing task", async () => {
      const { procs } = await setup();
      const result = await procs.deleteTask.handler({ taskId: "ghost" });
      expect(result.isError).toBe(true);
      expect(result.content[0]!.text).toContain("NOT_FOUND");
    });
  });

  describe("MCP tools integration", () => {
    it("getTools returns functional BuiltTool array", async () => {
      const storage = createMemoryAdapter();
      await taskQueue.initialize(storage);

      const tools = taskQueue.getTools(storage, "mcp-user");
      expect(tools).toHaveLength(6);

      // Use a tool through getTools
      const createTool = tools.find((t) => t.name === "create_task")!;
      const result = await createTool.handler({ title: "MCP task", description: "via tools" });
      expect(result.isError).toBeUndefined();

      const listTool = tools.find((t) => t.name === "list_tasks")!;
      const listResult = await listTool.handler({});
      const items = JSON.parse(listResult.content[0]!.text!);
      expect(items).toHaveLength(1);
    });
  });
});

import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";

