      expect(cache.info("nonexistent")).toBeUndefined();
    });

    it("should include TTL info when TTL is set", () => {
      mockPerformanceNow();
      const cache = new LRUCache<string, { value: string }>({
        max: 10,
        ttl: 100,
      });
