import { describe, expect, it } from "vitest";
import { getPartsStreaming } from "@/lib/get-parts";
import type { ParsingState } from "@/lib/interfaces";

function freshState(): ParsingState {
  return {
    isInCodeBlock: false,
    accumulatedContent: "",
    isInDiffBlock: false,
    accumulatedDiffContent: "",
  };
}

describe("getPartsStreaming", () => {
  describe("plain text", () => {
    it("returns a single text part for plain text", () => {
      const { parts } = getPartsStreaming("Hello world", false, freshState());
      expect(parts).toHaveLength(1);
      expect(parts[0]).toEqual({ type: "text", content: "Hello world" });
    });

    it("returns empty parts for empty string", () => {
      const { parts } = getPartsStreaming("", false, freshState());
      expect(parts).toHaveLength(0);
    });

    it("trims whitespace from text parts", () => {
      const { parts } = getPartsStreaming("  hello  ", false, freshState());
      expect(parts[0]!.content).toBe("hello");
    });
  });

  describe("code blocks", () => {
    it("extracts a typescript code block", () => {
      const text = "Some text\n```typescript\nconst x = 1;\n```\nMore text";
      const { parts } = getPartsStreaming(text, false, freshState());
      const codePart = parts.find((p) => p.type === "code");
      expect(codePart).toBeTruthy();
      expect(codePart!.language).toBe("typescript");
      expect(codePart!.content).toContain("const x = 1;");
    });

    it("extracts a javascript code block with 'js' shorthand", () => {
      const text = "```js\nconsole.log('hello');\n```";
      const { parts } = getPartsStreaming(text, false, freshState());
      const codePart = parts.find((p) => p.type === "code");
      expect(codePart!.language).toBe("javascript");
    });

    it("extracts a python code block with 'py' shorthand", () => {
      const text = "```py\nprint('hello')\n```";
      const { parts } = getPartsStreaming(text, false, freshState());
      const codePart = parts.find((p) => p.type === "code");
      expect(codePart!.language).toBe("python");
    });

    it("uses 'plaintext' for unknown language", () => {
      const text = "```unknownlang\nsome code\n```";
      const { parts } = getPartsStreaming(text, false, freshState());
      const codePart = parts.find((p) => p.type === "code");
      // Unknown language: falls back to lowercased value from LanguageMap or the lang itself
      expect(codePart).toBeTruthy();
    });

    it("produces text + code + text parts", () => {
      const text = "Before\n```typescript\ncode\n```\nAfter";
      const { parts } = getPartsStreaming(text, false, freshState());
      expect(parts.some((p) => p.type === "text" && p.content.includes("Before"))).toBe(true);
      expect(parts.some((p) => p.type === "code")).toBe(true);
      expect(parts.some((p) => p.type === "text" && p.content.includes("After"))).toBe(true);
    });

    it("handles incomplete code block (no closing ```)", () => {
      const text = "```typescript\nconst x = 1;";
      const state = freshState();
      const { parts } = getPartsStreaming(text, false, state);
      // Should produce a code part even without closing backticks
      const codePart = parts.find((p) => p.type === "code");
      expect(codePart).toBeTruthy();
    });
  });

  describe("diff blocks", () => {
    it("converts SEARCH/REPLACE to code diff block", () => {
      const text = `<<<<<<< SEARCH
old code
=======
new code
>>>>>>> REPLACE`;
      const { parts } = getPartsStreaming(text, false, freshState());
      const codePart = parts.find((p) => p.type === "code");
      expect(codePart).toBeTruthy();
      expect(codePart!.language).toBe("diff");
    });

    it("handles incomplete diff block (state tracking)", () => {
      const partial = "<<<<<<< SEARCH\nold code\n=======\nnew code";
      const state = freshState();
      const { parts, state: newState } = getPartsStreaming(partial, false, state);
      expect(newState.isInDiffBlock).toBe(true);
      // Should have a code part with accumulated diff content
      const codePart = parts.find((p) => p.type === "code" && p.language === "diff");
      expect(codePart).toBeTruthy();
    });

    it("completes an ongoing diff block when closing marker arrives", () => {
      const partialState: ParsingState = {
        isInCodeBlock: false,
        accumulatedContent: "",
        isInDiffBlock: true,
        accumulatedDiffContent: "<<<<<<< SEARCH\nold\n=======\nnew\n",
      };
      const continuation = ">>>>>>> REPLACE";
      const { parts, state } = getPartsStreaming(continuation, false, partialState);
      expect(state.isInDiffBlock).toBe(false);
      const codePart = parts.find((p) => p.language === "diff");
      expect(codePart).toBeTruthy();
    });

    it("handles text before a diff block", () => {
      const text = "Introduction text.\n<<<<<<< SEARCH\nold\n=======\nnew\n>>>>>>> REPLACE";
      const { parts } = getPartsStreaming(text, false, freshState());
      expect(parts.some((p) => p.type === "text")).toBe(true);
      expect(parts.some((p) => p.type === "code" && p.language === "diff")).toBe(true);
    });
  });

  describe("user message cleaning", () => {
    it("extracts content inside <user_prompt> tag for user messages", () => {
      const text = "<user_prompt>hello from user</user_prompt>";
      const { parts } = getPartsStreaming(text, true, freshState());
      expect(parts[0]!.content).toContain("hello from user");
    });

    it("strips system context from user messages", () => {
      const text = "System context.\nThe user's first message follows:\nActual user message";
      const { parts } = getPartsStreaming(text, true, freshState());
      expect(parts[0]!.content).toContain("Actual user message");
      expect(parts[0]!.content).not.toContain("System context");
    });

    it("strips system reminder suffix from user messages", () => {
      const text = "User message. Reminder from the system: ignore this";
      const { parts } = getPartsStreaming(text, true, freshState());
      expect(parts[0]!.content).toContain("User message.");
      expect(parts[0]!.content).not.toContain("Reminder from the system");
    });

    it("passes text unchanged for non-user messages", () => {
      const text = "The user's first message follows:\nOriginal message";
      const { parts } = getPartsStreaming(text, false, freshState());
      // isUser=false: no cleaning
      expect(parts[0]!.content).toContain("user's first message");
    });
  });

  describe("state handling", () => {
    it("uses default state when not provided", () => {
      const { parts } = getPartsStreaming("hello", false);
      expect(parts[0]!.content).toBe("hello");
    });

    it("returns updated state for ongoing incomplete code block", () => {
      const state = freshState();
      state.isInCodeBlock = true;
      state.accumulatedContent = "partial ";
      const { parts } = getPartsStreaming("remaining code", false, state);
      const codePart = parts.find((p) => p.type === "code");
      expect(codePart).toBeTruthy();
    });
  });
});

import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";

// Manual IndexedDB mock
function createMockIDB() {
  const stores: Record<string, Map<string, unknown>> = {};

  const mockObjectStore = (name: string) => {
    if (!stores[name]) stores[name] = new Map();
    const store = stores[name]!;

    return {
      get(key: string) {
        const result = store.get(key);
        const req = {
          result,
          onsuccess: null as (() => void) | null,
          onerror: null as (() => void) | null,
        };
        queueMicrotask(() => req.onsuccess?.());
        return req;
      },
      put(value: { key: string }) {
        store.set(value.key, value);
        const req = {
          result: undefined,
          onsuccess: null as (() => void) | null,
          onerror: null as (() => void) | null,
        };
        queueMicrotask(() => req.onsuccess?.());
        return req;
      },
      openCursor() {
        const entries = [...store.entries()];
        let index = 0;
        const req = {
          result: null as unknown,
          onsuccess: null as (() => void) | null,
          onerror: null as (() => void) | null,
        };
        const advance = () => {
          if (index < entries.length) {
            const [key, value] = entries[index]!;
            index++;
            req.result = {
              value,
              key,
              delete: () => {
                store.delete(key);
              },
              continue: () => {
                queueMicrotask(advance);
              },
            };
          } else {
            req.result = null;
          }
          req.onsuccess?.();
        };
        queueMicrotask(advance);
        return req;
      },
    };
  };

  const mockTransaction = (storeNames: string | string[], _mode?: string) => {
    const names = typeof storeNames === "string" ? [storeNames] : storeNames;
    return {
      objectStore: (name: string) => {
        if (!names.includes(name)) {
          throw new Error(`Store ${name} not in transaction`);
        }
        return mockObjectStore(name);
      },
    };
  };

  const objectStoreNames = { contains: (name: string) => !!stores[name] };

  const mockDB = {
    transaction: mockTransaction,
    close: vi.fn(),
    objectStoreNames,
    createObjectStore: (name: string, _opts?: unknown) => {
      stores[name] = new Map();
    },
  };

  const mockOpen = (_name: string, _version?: number) => {
    const req = {
      result: mockDB,
      onupgradeneeded: null as (() => void) | null,
      onsuccess: null as (() => void) | null,
      onerror: null as (() => void) | null,
    };
    queueMicrotask(() => {
      req.onupgradeneeded?.();
      queueMicrotask(() => req.onsuccess?.());
    });
    return req;
  };

  return { open: mockOpen, stores };
}

describe("idb-cache", () => {
  let mockIDB: ReturnType<typeof createMockIDB>;

  beforeEach(() => {
    vi.resetModules();
    mockIDB = createMockIDB();
    vi.stubGlobal("indexedDB", { open: mockIDB.open });
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it("should set and get ATA cache entries", async () => {
    const { getAtaCache, setAtaCache } = await import("@/lib/idb-cache");

    await setAtaCache("https://unpkg.com/@types/react/index.d.ts", "declare module react {}");
    const result = await getAtaCache("https://unpkg.com/@types/react/index.d.ts");

    expect(result).toBe("declare module react {}");
  });

  it("should return null for missing ATA cache entries", async () => {
    const { getAtaCache } = await import("@/lib/idb-cache");
    const result = await getAtaCache("https://nonexistent.com/types.d.ts");
    expect(result).toBeNull();
  });

  it("should set and get WASM module entries", async () => {
    const { getWasmModule, setWasmModule } = await import("@/lib/idb-cache");

    const buffer = new ArrayBuffer(8);
    const view = new Uint8Array(buffer);
    view.set([0, 97, 115, 109, 1, 0, 0, 0]); // WASM magic bytes

    await setWasmModule("esbuild-wasm", buffer);
    const result = await getWasmModule("esbuild-wasm");

    expect(result).toBeInstanceOf(ArrayBuffer);
    expect(new Uint8Array(result!)[0]).toBe(0);
    expect(new Uint8Array(result!)[1]).toBe(97);
  });

  it("should return null for missing WASM module entries", async () => {
    const { getWasmModule } = await import("@/lib/idb-cache");
    const result = await getWasmModule("nonexistent");
    expect(result).toBeNull();
  });

  it("should prune expired ATA entries", async () => {
    const { getAtaCache, setAtaCache, pruneExpiredEntries } = await import("@/lib/idb-cache");

    await setAtaCache("https://old.com/types.d.ts", "old content");

    // Manually age the entry by modifying the store
    const ataStore = mockIDB.stores["ata-cache"];
    if (ataStore) {
      const entry = ataStore.get("https://old.com/types.d.ts") as {
        timestamp: number;
      };
      if (entry) {
        entry.timestamp = Date.now() - 8 * 24 * 60 * 60 * 1000; // 8 days ago
      }
    }

    await pruneExpiredEntries();

    const result = await getAtaCache("https://old.com/types.d.ts");
    expect(result).toBeNull();
  });

  it("should keep fresh entries during prune", async () => {
    const { getAtaCache, setAtaCache, pruneExpiredEntries } = await import("@/lib/idb-cache");

    await setAtaCache("https://fresh.com/types.d.ts", "fresh content");
    await pruneExpiredEntries();

    const result = await getAtaCache("https://fresh.com/types.d.ts");
    expect(result).toBe("fresh content");
  });

  it("should return expired entries as null without pruning", async () => {
    const { getAtaCache, setAtaCache } = await import("@/lib/idb-cache");

    await setAtaCache("https://stale.com/types.d.ts", "stale");

    // Age the entry beyond TTL
    const ataStore = mockIDB.stores["ata-cache"];
    if (ataStore) {
      const entry = ataStore.get("https://stale.com/types.d.ts") as {
        timestamp: number;
      };
      if (entry) {
        entry.timestamp = Date.now() - 8 * 24 * 60 * 60 * 1000;
      }
    }

    const result = await getAtaCache("https://stale.com/types.d.ts");
    expect(result).toBeNull();
  });

  it("should gracefully handle IDB errors in getAtaCache", async () => {
    vi.stubGlobal("indexedDB", {
      open: () => {
        const req = {
          result: null,
          onupgradeneeded: null,
          onsuccess: null,
          onerror: null as (() => void) | null,
          error: new Error("IDB error"),
        };
        queueMicrotask(() => req.onerror?.());
        return req;
      },
    });

    vi.resetModules();
    const { getAtaCache } = await import("@/lib/idb-cache");
    const result = await getAtaCache("https://example.com");
    expect(result).toBeNull();
  });

  it("should gracefully handle IDB errors in setAtaCache", async () => {
    vi.stubGlobal("indexedDB", {
      open: () => {
        const req = {
          result: null,
          onupgradeneeded: null,
          onsuccess: null,
          onerror: null as (() => void) | null,
          error: new Error("IDB error"),
        };
        queueMicrotask(() => req.onerror?.());
        return req;
      },
    });

    vi.resetModules();
    const { setAtaCache } = await import("@/lib/idb-cache");
    // Should not throw
    await expect(setAtaCache("https://example.com", "content")).resolves.toBeUndefined();
  });

  it("should create object stores on DB upgrade", async () => {
    const { getAtaCache } = await import("@/lib/idb-cache");
    // Accessing getAtaCache triggers openDB which triggers onupgradeneeded
    await getAtaCache("test");
    expect(mockIDB.stores["ata-cache"]).toBeDefined();
    expect(mockIDB.stores["wasm-cache"]).toBeDefined();
  });
});

