describe("MCP tool: verify-session", () => {
  beforeEach(() => {
    vi.clearAllMocks();
    registeredTools.length = 0;
    mockGetSession = vi.fn(async (..._args: unknown[]) => null);
  });

  async function getVerifySessionTool() {
    const req = makeMcpRequest("POST");
    await worker.fetch(req, makeEnv());
    return registeredTools.find((t) => t.name === "verify-session");
  }

  it("returns valid:false when session is null", async () => {
    mockGetSession.mockResolvedValueOnce(null);
    const tool = await getVerifySessionTool();
    expect(tool).toBeDefined();
    const result = (await tool!.handler({ sessionToken: "invalid-token" })) as {
      content: Array<{ text: string }>;
    };
    const data = JSON.parse(result.content[0]!.text);
    expect(data.valid).toBe(false);
  });

  it("returns valid:false when sessionResult has no session property", async () => {
    mockGetSession.mockResolvedValueOnce({ user: { id: "u1" } });
    const tool = await getVerifySessionTool();
    const result = (await tool!.handler({ sessionToken: "token" })) as {
      content: Array<{ text: string }>;
    };
    const data = JSON.parse(result.content[0]!.text);
    expect(data.valid).toBe(false);
  });

  it("returns valid:true with user and session when session exists", async () => {
    mockGetSession.mockResolvedValueOnce({
      session: { id: "sess-1", token: "tok" },
      user: { id: "user-1", email: "test@example.com", name: "Test User" },
    });
    const tool = await getVerifySessionTool();
    const result = (await tool!.handler({ sessionToken: "valid-token" })) as {
      content: Array<{ text: string }>;
    };
    const data = JSON.parse(result.content[0]!.text);
    expect(data.valid).toBe(true);
    expect(data.user.id).toBe("user-1");
    expect(data.user.email).toBe("test@example.com");
    expect(data.session.id).toBe("sess-1");
  });

  it("sets cookie header with the session token", async () => {
    mockGetSession.mockImplementationOnce(async ({ headers }: { headers: Headers }) => {
      const cookie = headers.get("cookie") ?? "";
      expect(cookie).toContain("better-auth.session_token=my-token");
      return { session: { id: "s1" }, user: { id: "u1" } };
    });
    const tool = await getVerifySessionTool();
    await tool!.handler({ sessionToken: "my-token" });
  });

  it("returns text content type in response", async () => {
    mockGetSession.mockResolvedValueOnce(null);
    const tool = await getVerifySessionTool();
    const result = (await tool!.handler({ sessionToken: "tok" })) as {
      content: Array<{ type: string }>;
    };
    expect(result.content[0]!.type).toBe("text");
  });
});

describe("MCP tool: get-user-by-email", () => {
  beforeEach(() => {
    vi.clearAllMocks();
    registeredTools.length = 0;
    mockFindFirst = vi.fn(async (..._args: unknown[]) => null);
  });

  async function getEmailTool() {
    const req = makeMcpRequest("POST");
    await worker.fetch(req, makeEnv());
    return registeredTools.find((t) => t.name === "get-user-by-email");
  }

  it("returns found:false when user does not exist", async () => {
    mockFindFirst.mockResolvedValueOnce(null);
    const tool = await getEmailTool();
    expect(tool).toBeDefined();
    const result = (await tool!.handler({ email: "notfound@example.com" })) as {
      content: Array<{ text: string }>;
    };
    const data = JSON.parse(result.content[0]!.text);
    expect(data.found).toBe(false);
  });

  it("returns found:true with user fields when user exists", async () => {
    mockFindFirst.mockResolvedValueOnce({
      id: "user-42",
      email: "alice@example.com",
      name: "Alice",
      role: "admin",
      image: "https://example.com/avatar.png",
    });
    const tool = await getEmailTool();
    const result = (await tool!.handler({ email: "alice@example.com" })) as {
      content: Array<{ text: string }>;
    };
    const data = JSON.parse(result.content[0]!.text);
    expect(data.found).toBe(true);
    expect(data.user.id).toBe("user-42");
    expect(data.user.email).toBe("alice@example.com");
    expect(data.user.name).toBe("Alice");
    expect(data.user.role).toBe("admin");
  });

  it("only returns id, email, name, role — not image", async () => {
    mockFindFirst.mockResolvedValueOnce({
      id: "u1",
      email: "bob@example.com",
      name: "Bob",
      role: "user",
      image: "https://secret-image.example.com/photo.jpg",
    });
    const tool = await getEmailTool();
    const result = (await tool!.handler({ email: "bob@example.com" })) as {
      content: Array<{ text: string }>;
    };
    const data = JSON.parse(result.content[0]!.text);
    expect(data.user).not.toHaveProperty("image");
  });

  it("returns null role when user has no role set", async () => {
    mockFindFirst.mockResolvedValueOnce({
      id: "u2",
      email: "charlie@example.com",
      name: "Charlie",
      role: null,
    });
    const tool = await getEmailTool();
    const result = (await tool!.handler({ email: "charlie@example.com" })) as {
      content: Array<{ text: string }>;
    };
    const data = JSON.parse(result.content[0]!.text);
    expect(data.found).toBe(true);
    expect(data.user.role).toBeNull();
  });

  it("returns text content type", async () => {
    mockFindFirst.mockResolvedValueOnce(null);
    const tool = await getEmailTool();
    const result = (await tool!.handler({ email: "x@example.com" })) as {
      content: Array<{ type: string }>;
    };
    expect(result.content[0]!.type).toBe("text");
  });
});

import { expect, it, vi } from "vitest";
import type {
  CallToolResult,
  ImageStudioDeps,
  ToolContext,
} from "../../../src/mcp-tools/image-studio/types.js";

export function standardScenarios(config: {
  handler: (input: unknown, ctx: ToolContext) => Promise<CallToolResult> | CallToolResult;
  validInput: Record<string, unknown>;
  deps: ImageStudioDeps;
  resolvesImage?: boolean; // Checks IMAGE_NOT_FOUND when image is mocked as null
  resolvesImages?: boolean; // Checks RESOLVE_FAILED when images do not exist
  resolvesAlbum?: boolean; // Checks NOT_FOUND when album does not exist
  consumesCredits?: boolean; // Checks CREDIT_CONSUME_FAILED when credits insufficient
  createsJob?: boolean; // Checks JOB_CREATE_FAILED when job creation fails
  emitsEvent?: string[]; // Checks that specific events are emitted on success
}) {
  if (config.resolvesImage) {
    it("should return IMAGE_NOT_FOUND when image does not exist", async () => {
      // Because resolveImages requires array and resolvesImage checks that array isn't null/undefined
      // In the framework it actually resolves to either RESOLVE_FAILED or UNAUTHORIZED. The framework returns
      vi.mocked(config.deps.resolvers.resolveImages).mockResolvedValueOnce([]);
      vi.mocked(config.deps.resolvers.resolveImage).mockResolvedValueOnce(undefined as never);
      const result = await config.handler(config.validInput, {
        userId: "user-1",
        deps: config.deps,
        notify: vi.fn(),
      });

      expect(result).toMatchObject({
        isError: true,
        content: expect.arrayContaining([
          expect.objectContaining({
            type: "text",
            text: expect.stringMatching(/UNAUTHORIZED|NOT_FOUND|RESOLVE_FAILED/),
          }),
        ]),
      });
    });
  }

  if (config.consumesCredits) {
    it("should return CREDIT_CONSUME_FAILED when credits are insufficient", async () => {
      if (config.deps.credits.calculateGenerationCost) {
        vi.mocked(config.deps.credits.calculateGenerationCost).mockReturnValue(10);
      }
      vi.mocked(config.deps.credits.consume).mockResolvedValueOnce({
        success: false,
        remaining: 0,
        error: "Insufficient credits mock",
      });

      const result = await config.handler(config.validInput, {
        userId: "user-1",
        deps: config.deps,
        notify: vi.fn(),
      });

      expect(result).toMatchObject({
        isError: true,
        content: expect.arrayContaining([
          expect.objectContaining({
            type: "text",
            text: expect.stringContaining("CREDIT_CONSUME_FAILED"),
          }),
        ]),
      });
    });
  }

  if (config.createsJob) {
    it("should return JOB_CREATE_FAILED when job creation fails", async () => {
      vi.mocked(config.deps.db.jobCreate).mockRejectedValueOnce(new Error("DB Error mock"));

      const result = await config.handler(config.validInput, {
        userId: "user-1",
        deps: config.deps,
        notify: vi.fn(),
      });

      expect(result).toMatchObject({
        isError: true,
        content: expect.arrayContaining([
          expect.objectContaining({
            type: "text",
            text: expect.stringContaining("JOB_CREATE_FAILED"),
          }),
        ]),
      });
    });
  }

  if (config.emitsEvent && config.emitsEvent.length > 0) {
    it(`should emit events: ${config.emitsEvent.join(", ")}`, async () => {
      const notify = vi.fn();
      const result = await config.handler(config.validInput, {
        userId: "user-1",
        deps: config.deps,
        notify,
      });

      expect(result.isError).toBeFalsy();

      for (const eventType of config.emitsEvent!) {
        expect(notify).toHaveBeenCalledWith(expect.objectContaining({ type: eventType }));
      }
    });
  }
}

import { beforeEach, describe, expect, it, vi } from "vitest";
