describe("consumeCreditsOrError", () => {
  let deps: NanoDeps;
  let mocks: ReturnType<typeof createMockImageStudioDeps>["mocks"];

  beforeEach(() => {
    const mocked = createMockImageStudioDeps();
    deps = mocked.deps;
    mocks = mocked.mocks;
  });

  it("should return empty object on successful credit consumption", async () => {
    mocks.credits.consume.mockResolvedValue({ success: true, remaining: 90 });

    const result = await consumeCreditsOrError(deps, "user-1", 10, "enhance", "img-1");

    expect(result.error).toBeUndefined();
  });

  it("should call credits.consume with correct params", async () => {
    mocks.credits.consume.mockResolvedValue({ success: true, remaining: 90 });

    await consumeCreditsOrError(deps, "user-1", 5, "generate", "job-1");

    expect(mocks.credits.consume).toHaveBeenCalledWith({
      userId: "user-1",
      amount: 5,
      source: "generate",
      sourceId: "job-1",
    });
  });

  it("should return CREDIT_CONSUME_FAILED when consume returns success:false", async () => {
    mocks.credits.consume.mockResolvedValue({
      success: false,
      remaining: 0,
      error: "Balance too low",
    });

    const result = await consumeCreditsOrError(deps, "user-1", 10, "enhance");

    expect(result.error).toBeDefined();
    expect(result.error!.isError).toBe(true);
    expect(result.error!.content[0].text).toContain("CREDIT_CONSUME_FAILED");
    expect(result.error!.content[0].text).toContain("Balance too low");
  });

  it("should return CREDIT_CONSUME_FAILED when consume throws", async () => {
    mocks.credits.consume.mockRejectedValue(new Error("Network error"));

    const result = await consumeCreditsOrError(deps, "user-1", 10, "enhance");

    expect(result.error).toBeDefined();
    expect(result.error!.isError).toBe(true);
    expect(result.error!.content[0].text).toContain("CREDIT_CONSUME_FAILED");
  });

  it("should use fallback error message when consume returns no error string", async () => {
    mocks.credits.consume.mockResolvedValue({ success: false, remaining: 0 });

    const result = await consumeCreditsOrError(deps, "user-1", 10, "enhance");

    expect(result.error!.content[0].text).toContain("Failed to consume credits");
  });

  it("should notify with credits:consumed event when ctx.notify is provided", async () => {
    mocks.credits.consume.mockResolvedValue({ success: true, remaining: 90 });
    const notify = vi.fn();

    const result = await consumeCreditsOrError(deps, "user-1", 10, "enhance", "img-1", {
      notify,
    } as unknown as ToolContext);

    expect(result.error).toBeUndefined();
    expect(notify).toHaveBeenCalledWith(expect.objectContaining({ type: "credits:consumed" }));
  });

  it("should not throw when ctx is undefined", async () => {
    mocks.credits.consume.mockResolvedValue({ success: true, remaining: 90 });

    const result = await consumeCreditsOrError(deps, "user-1", 10, "enhance", undefined, undefined);

    expect(result.error).toBeUndefined();
  });

  it("should not notify when ctx.notify is undefined", async () => {
    mocks.credits.consume.mockResolvedValue({ success: true, remaining: 90 });

    const result = await consumeCreditsOrError(
      deps,
      "user-1",
      10,
      "enhance",
      "img-1",
      {} as unknown as ToolContext,
    );

    expect(result.error).toBeUndefined();
  });
});

import { describe, expect, it, vi } from "vitest";
import type { GatewayTransport } from "../../src/mcp-tools/openclaw/core-logic/types.js";
import { createMcpBridge } from "../../src/mcp-tools/openclaw/core-logic/bridge.js";

function mockTransport(): GatewayTransport & {
  request: ReturnType<typeof vi.fn>;
} {
  return { request: vi.fn() };
}

describe("createMcpBridge", () => {
  it("listTools() includes built-in chat tool by default", () => {
    const transport = mockTransport();
    const bridge = createMcpBridge({
      transport,
      serverInfo: { name: "test", version: "0.0.1" },
    });

    const tools = bridge.listTools();
    expect(tools).toHaveLength(2);
    expect(tools.map((t) => t.name)).toContain("chat");
    expect(tools.map((t) => t.name)).toContain("openclaw_feedback");
    const chatTool = tools.find((t) => t.name === "chat")!;
    expect(chatTool.description).toContain("OpenClaw");
  });

  it("loadGatewayTools() registers tools from tools.list RPC response", async () => {
    const transport = mockTransport();
    transport.request.mockResolvedValue({
      tools: [
        {
          name: "search",
          description: "Search",
          parameters: { type: "object", properties: { q: { type: "string" } } },
        },
        { name: "calc", description: "Calculate" },
      ],
      sessionKey: "agent:test:test",
    });

    const bridge = createMcpBridge({
      transport,
      serverInfo: { name: "test", version: "0.0.1" },
    });

    await bridge.loadGatewayTools();
    const tools = bridge.listTools();

    expect(tools).toHaveLength(4); // chat + openclaw_feedback + search + calc
    expect(tools.map((t) => t.name)).toContain("search");
    expect(tools.map((t) => t.name)).toContain("calc");
  });

  it("loadGatewayTools() falls back to chat-only when tools.list throws", async () => {
    const transport = mockTransport();
    transport.request.mockRejectedValue(new Error("not available"));

    const bridge = createMcpBridge({
      transport,
      serverInfo: { name: "test", version: "0.0.1" },
    });

    await bridge.loadGatewayTools();
    const tools = bridge.listTools();

    expect(tools).toHaveLength(2);
    expect(tools.map((t) => t.name)).toContain("chat");
    expect(tools.map((t) => t.name)).toContain("openclaw_feedback");
  });

  it("loadGatewayTools() is idempotent", async () => {
    const transport = mockTransport();
    transport.request.mockResolvedValue({
      tools: [{ name: "tool1" }],
    });

    const bridge = createMcpBridge({
      transport,
      serverInfo: { name: "test", version: "0.0.1" },
    });

    await bridge.loadGatewayTools();
    await bridge.loadGatewayTools();

    expect(transport.request).toHaveBeenCalledTimes(1);
  });

  it('callTool("chat", ...) sends chat.send RPC and returns text', async () => {
    const transport = mockTransport();
    transport.request.mockResolvedValue({
      message: { content: [{ type: "text", text: "Hello back!" }] },
    });

    const bridge = createMcpBridge({
      transport,
      serverInfo: { name: "test", version: "0.0.1" },
    });

    const result = await bridge.callTool("chat", { message: "Hello" });

    expect(result).toEqual({
      content: [{ type: "text", text: "Hello back!" }],
    });
    expect(transport.request).toHaveBeenCalledWith(
      "chat.send",
      { sessionKey: "agent:main:main", message: "Hello" },
      { expectFinal: true },
    );
  });

  it('callTool("chat", {}) returns error when message is missing', async () => {
    const transport = mockTransport();
    const bridge = createMcpBridge({
      transport,
      serverInfo: { name: "test", version: "0.0.1" },
    });

    const result = await bridge.callTool("chat", {});

    expect(result.isError).toBe(true);
    expect(result.content[0].text).toContain("message is required");
  });

  it('callTool("chat", ...) passes expectFinal: true', async () => {
    const transport = mockTransport();
    transport.request.mockResolvedValue({
      message: { content: [{ type: "text", text: "ok" }] },
    });

    const bridge = createMcpBridge({
      transport,
      serverInfo: { name: "test", version: "0.0.1" },
    });

    await bridge.callTool("chat", { message: "hi" });

    expect(transport.request).toHaveBeenCalledWith("chat.send", expect.any(Object), {
      expectFinal: true,
    });
  });

  it('callTool("chat", ...) uses custom session key', async () => {
    const transport = mockTransport();
    transport.request.mockResolvedValue({
      message: { content: [{ type: "text", text: "ok" }] },
    });

    const bridge = createMcpBridge({
      transport,
      serverInfo: { name: "test", version: "0.0.1" },
    });

    await bridge.callTool("chat", {
      message: "hi",
      session: "agent:custom:session",
    });

    expect(transport.request).toHaveBeenCalledWith(
      "chat.send",
      { sessionKey: "agent:custom:session", message: "hi" },
      { expectFinal: true },
    );
  });

  it("chat RPC error returns wrapped error content", async () => {
    const transport = mockTransport();
    transport.request.mockRejectedValue(new Error("connection lost"));

