    });

    it("returns formatted text by default", async () => {
      const report: ScanReport = {
        rootDir: "/project",
        filePattern: "**/*.md",
        filesScanned: 1,
        summary: { totalLinks: 3, broken: 1, warnings: 0, ok: 2, skipped: 0, errors: 0 },
