import { beforeEach, describe, expect, it, vi } from "vitest";
import { MutationType } from "../../../../../src/core/react-engine/react-worker-dom/bridge/protocol.js";

// We need to mock Worker since jsdom doesn't support it fully
class MockWorker {
  onmessage: ((ev: MessageEvent) => void) | null = null;
  postMessage = vi.fn();
  terminate = vi.fn();
  _url: string;
  _options: unknown;

  constructor(url: string, options?: unknown) {
    this._url = url;
    this._options = options;
  }
}

vi.stubGlobal("Worker", MockWorker);

// Import after stubbing
const { MainThreadApplier } = await import(
  "../../../../../src/core/react-engine/react-worker-dom/bridge/main-applier.js"
);

describe("MainThreadApplier", () => {
  let container: HTMLElement;
  let applier: InstanceType<typeof MainThreadApplier>;
  let mockWorker: MockWorker;

  beforeEach(() => {
    container = document.createElement("div");
    document.body.appendChild(container);
    applier = new MainThreadApplier(container, "blob:fake-url");
    // Get reference to the mock worker
    mockWorker = (applier as unknown as Record<string, unknown>).worker as MockWorker;
  });

  function sendMutations(mutations: unknown[]) {
    mockWorker.onmessage?.({ data: { kind: "mutations", mutations } } as MessageEvent);
  }

  it("registers container as node 0", () => {
    const nodeMap = (applier as unknown as Record<string, unknown>).nodeMap as Map<number, Node>;
    expect(nodeMap.get(0)).toBe(container);
  });

  it("CREATE_ELEMENT mutation creates an element", () => {
    sendMutations([{ type: MutationType.CREATE_ELEMENT, targetId: 1, tagName: "div" }]);
    const nodeMap = (applier as unknown as Record<string, unknown>).nodeMap as Map<number, Node>;
    const el = nodeMap.get(1);
    expect(el).toBeDefined();
    expect((el as Element).tagName.toLowerCase()).toBe("div");
  });

  it("CREATE_ELEMENT_NS mutation creates namespaced element", () => {
    sendMutations([
      {
        type: MutationType.CREATE_ELEMENT_NS,
        targetId: 2,
        tagName: "svg",
        namespace: "http://www.w3.org/2000/svg",
      },
    ]);
    const nodeMap = (applier as unknown as Record<string, unknown>).nodeMap as Map<number, Node>;
    const el = nodeMap.get(2);
    expect(el).toBeDefined();
    expect((el as Element).namespaceURI).toBe("http://www.w3.org/2000/svg");
  });

  it("CREATE_TEXT mutation creates text node", () => {
    sendMutations([{ type: MutationType.CREATE_TEXT, targetId: 3, value: "hello" }]);
    const nodeMap = (applier as unknown as Record<string, unknown>).nodeMap as Map<number, Node>;
    const node = nodeMap.get(3);
    expect(node).toBeDefined();
    expect((node as Text).data).toBe("hello");
  });

  it("CREATE_TEXT with null value", () => {
    sendMutations([{ type: MutationType.CREATE_TEXT, targetId: 10, value: null }]);
    const nodeMap = (applier as unknown as Record<string, unknown>).nodeMap as Map<number, Node>;
    expect((nodeMap.get(10) as Text).data).toBe("");
  });

  it("APPEND_CHILD appends child to parent", () => {
    sendMutations([
      { type: MutationType.CREATE_ELEMENT, targetId: 4, tagName: "span" },
      { type: MutationType.APPEND_CHILD, targetId: 4, parentId: 0 },
    ]);
    expect(container.children).toHaveLength(1);
    expect(container.children[0]!.tagName.toLowerCase()).toBe("span");
  });

  it("APPEND_CHILD skips missing parent", () => {
    sendMutations([
      { type: MutationType.CREATE_ELEMENT, targetId: 5, tagName: "p" },
      { type: MutationType.APPEND_CHILD, targetId: 5, parentId: 999 },
    ]);
    // Should not throw and no children appended to container
    expect(container.children).toHaveLength(0);
  });

  it("INSERT_BEFORE inserts element before reference", () => {
    sendMutations([
      { type: MutationType.CREATE_ELEMENT, targetId: 6, tagName: "div" },
      { type: MutationType.CREATE_ELEMENT, targetId: 7, tagName: "span" },
      { type: MutationType.APPEND_CHILD, targetId: 6, parentId: 0 },
      { type: MutationType.INSERT_BEFORE, targetId: 7, parentId: 0, refId: 6 },
    ]);
    expect(container.children).toHaveLength(2);
    expect(container.children[0]!.tagName.toLowerCase()).toBe("span");
  });

  it("INSERT_BEFORE with missing ref (inserts at end)", () => {
    sendMutations([
      { type: MutationType.CREATE_ELEMENT, targetId: 11, tagName: "div" },
      { type: MutationType.CREATE_ELEMENT, targetId: 12, tagName: "span" },
      { type: MutationType.APPEND_CHILD, targetId: 11, parentId: 0 },
      { type: MutationType.INSERT_BEFORE, targetId: 12, parentId: 0, refId: 999 },
    ]);
    // refId 999 not found, so insertBefore(child, null) => append
    expect(container.children).toHaveLength(2);
  });

  it("REMOVE_CHILD removes element from parent", () => {
    sendMutations([
      { type: MutationType.CREATE_ELEMENT, targetId: 8, tagName: "div" },
      { type: MutationType.APPEND_CHILD, targetId: 8, parentId: 0 },
    ]);
    expect(container.children).toHaveLength(1);
    sendMutations([{ type: MutationType.REMOVE_CHILD, targetId: 8, parentId: 0 }]);
    expect(container.children).toHaveLength(0);
  });

  it("REMOVE_CHILD skips when parent/child not found", () => {
    expect(() =>
      sendMutations([{ type: MutationType.REMOVE_CHILD, targetId: 999, parentId: 0 }]),
    ).not.toThrow();
  });

  it("SET_ATTRIBUTE sets attribute on element", () => {
    sendMutations([
      { type: MutationType.CREATE_ELEMENT, targetId: 20, tagName: "div" },
      { type: MutationType.SET_ATTRIBUTE, targetId: 20, name: "data-x", value: "hello" },
    ]);
    const nodeMap = (applier as unknown as Record<string, unknown>).nodeMap as Map<number, Node>;
    expect((nodeMap.get(20) as Element).getAttribute("data-x")).toBe("hello");
  });

  it("REMOVE_ATTRIBUTE removes attribute from element", () => {
    sendMutations([
      { type: MutationType.CREATE_ELEMENT, targetId: 21, tagName: "div" },
      { type: MutationType.SET_ATTRIBUTE, targetId: 21, name: "data-y", value: "val" },
      { type: MutationType.REMOVE_ATTRIBUTE, targetId: 21, name: "data-y" },
    ]);
    const nodeMap = (applier as unknown as Record<string, unknown>).nodeMap as Map<number, Node>;
    expect((nodeMap.get(21) as Element).hasAttribute("data-y")).toBe(false);
  });

  it("SET_STYLE sets style property on HTMLElement", () => {
    sendMutations([
      { type: MutationType.CREATE_ELEMENT, targetId: 22, tagName: "div" },
      { type: MutationType.SET_STYLE, targetId: 22, name: "color", value: "red" },
    ]);
    const nodeMap = (applier as unknown as Record<string, unknown>).nodeMap as Map<number, Node>;
    expect((nodeMap.get(22) as HTMLElement).style.color).toBe("red");
  });

  it("SET_TEXT sets text node data", () => {
    sendMutations([
      { type: MutationType.CREATE_TEXT, targetId: 23, value: "initial" },
      { type: MutationType.SET_TEXT, targetId: 23, value: "updated" },
    ]);
    const nodeMap = (applier as unknown as Record<string, unknown>).nodeMap as Map<number, Node>;
    expect((nodeMap.get(23) as Text).data).toBe("updated");
  });

  it("SET_TEXT_CONTENT sets textContent", () => {
    sendMutations([
      { type: MutationType.CREATE_ELEMENT, targetId: 24, tagName: "div" },
      { type: MutationType.SET_TEXT_CONTENT, targetId: 24, value: "text content" },
    ]);
    const nodeMap = (applier as unknown as Record<string, unknown>).nodeMap as Map<number, Node>;
    expect((nodeMap.get(24) as HTMLElement).textContent).toBe("text content");
  });

  it("destroy terminates worker and clears nodeMap", () => {
    applier.destroy();
    expect(mockWorker.terminate).toHaveBeenCalled();
    const nodeMap = (applier as unknown as Record<string, unknown>).nodeMap as Map<number, Node>;
    expect(nodeMap.size).toBe(0);
  });

  it("ignores non-mutations messages", () => {
    expect(() => {
      mockWorker.onmessage?.({ data: { kind: "other" } } as MessageEvent);
    }).not.toThrow();
  });
});

import { describe, expect, it } from "vitest";
import {
  countChildren,
  forEachChildren,
  mapChildren,
  onlyChild,
  toArray,
} from "../../../../src/core/react-engine/react/ReactChildren.js";
import {
  createElement,
  isValidElement,
} from "../../../../src/core/react-engine/react/ReactElement.js";

describe("mapChildren", () => {
  it("returns null for null children", () => {
    expect(mapChildren(null, (c) => c)).toBeNull();
  });

  it("returns undefined for undefined children", () => {
    expect(mapChildren(undefined, (c) => c)).toBeUndefined();
  });

  it("maps a single element", () => {
    const el = createElement("div", null);
    const result = mapChildren(el, (child) => child);
    expect(result).toHaveLength(1);
    expect(isValidElement(result![0])).toBe(true);
  });

  it("maps an array of elements", () => {
    const children = [createElement("div", null), createElement("span", null)];
    const result = mapChildren(children, (child) => child);
    expect(result).toHaveLength(2);
  });

  it("maps string children", () => {
    const result = mapChildren("hello", (child) => child);
    expect(result).toHaveLength(1);
    expect(result![0]).toBe("hello");
  });

  it("maps number children", () => {
    const result = mapChildren(42, (child) => child);
    expect(result).toHaveLength(1);
    expect(result![0]).toBe(42);
  });

  it("provides correct index to callback", () => {
    const children = [
      createElement("div", null),
      createElement("span", null),
      createElement("p", null),
    ];
    const indices: number[] = [];
    mapChildren(children, (child, index) => {
      indices.push(index);
      return child;
    });
    expect(indices).toEqual([0, 1, 2]);
  });

  it("callback transform is applied", () => {
    const el = createElement("div", null);
    const result = mapChildren(el, () => createElement("span", null));
    expect(result).toHaveLength(1);
    expect((result![0] as { type: string }).type).toBe("span");
  });

  it("skips null returns from callback", () => {
    const children = [createElement("div", null), createElement("span", null)];
    const result = mapChildren(children, (_child, index) => (index === 0 ? null : _child));
    // null returns are skipped
    expect(result).toHaveLength(1);
  });

  it("handles boolean children by treating as null (skipped when callback returns null)", () => {
    // Booleans become null internally; callback receives null and returns null,
    // which mapIntoArray does not push (null is falsy check: mappedChild != null fails)
    const result = mapChildren(true as unknown as null, (child) => child);
    expect(result).toHaveLength(0);
  });

  it("throws for plain object children", () => {
    expect(() => {
      mapChildren({ key: "value" } as unknown as null, (c) => c);
    }).toThrow();
  });
});

describe("forEachChildren", () => {
  it("calls callback for each child", () => {
    const children = [createElement("div", null), createElement("span", null)];
    const visited: unknown[] = [];
    forEachChildren(children, (child) => visited.push(child));
    expect(visited).toHaveLength(2);
  });

  it("returns void (not the children)", () => {
    const result = forEachChildren(createElement("div", null), () => {});
    expect(result).toBeUndefined();
  });

  it("handles null children gracefully", () => {
    expect(() => forEachChildren(null, () => {})).not.toThrow();
  });

  it("provides index to callback", () => {
    const indices: number[] = [];
    forEachChildren([createElement("a", null), createElement("b", null)], (_child, index) =>
      indices.push(index),
    );
    expect(indices).toEqual([0, 1]);
  });
});

describe("countChildren", () => {
  it("returns 0 for null", () => {
    expect(countChildren(null)).toBe(0);
  });

  it("returns 1 for a single element", () => {
    expect(countChildren(createElement("div", null))).toBe(1);
  });

  it("returns correct count for array", () => {
    const children = [
      createElement("div", null),
      createElement("span", null),
      createElement("p", null),
    ];
    expect(countChildren(children)).toBe(3);
  });

  it("returns 1 for a string child", () => {
    expect(countChildren("hello")).toBe(1);
  });

  it("returns 1 for a number child", () => {
    expect(countChildren(42)).toBe(1);
  });

  it("counts nested array children", () => {
    const nested = [
      createElement("div", null),
      [createElement("span", null), createElement("p", null)],
    ];
    expect(countChildren(nested)).toBe(3);
  });
});

describe("toArray", () => {
  it("returns empty array for null", () => {
    expect(toArray(null)).toEqual([]);
  });

  it("returns empty array for undefined", () => {
    expect(toArray(undefined)).toEqual([]);
  });

  it("returns array with single element for single child", () => {
    const el = createElement("div", null);
    const result = toArray(el);
    expect(result).toHaveLength(1);
    expect(isValidElement(result[0])).toBe(true);
  });

  it("flattens array children", () => {
    const children = [createElement("div", null), createElement("span", null)];
    const result = toArray(children);
    expect(result).toHaveLength(2);
  });

  it("returns array type", () => {
    const result = toArray(createElement("div", null));
    expect(Array.isArray(result)).toBe(true);
  });
});

describe("onlyChild", () => {
  it("returns the single child element", () => {
    const el = createElement("div", null);
    expect(onlyChild(el)).toBe(el);
  });

  it("throws for non-element children", () => {
    expect(() => onlyChild("text" as unknown as null)).toThrow(
      "React.Children.only expected to receive a single React element child.",
    );
  });

  it("throws for null", () => {
    expect(() => onlyChild(null)).toThrow();
  });

  it("throws for number", () => {
    expect(() => onlyChild(42 as unknown as null)).toThrow();
  });
});

import { describe, expect, it } from "vitest";
import { lazy } from "../../../../src/core/react-engine/react/ReactLazy.js";
import { REACT_LAZY_TYPE } from "../../../../src/core/react-engine/react/ReactSymbols.js";

describe("lazy", () => {
  it("creates lazy component with correct $$typeof", () => {
    const lazyComp = lazy(() => Promise.resolve({ default: () => null }));
    expect(lazyComp.$$typeof).toBe(REACT_LAZY_TYPE);
  });

  it("has _payload and _init", () => {
    const lazyComp = lazy(() => Promise.resolve({ default: () => null }));
    expect(lazyComp._payload).toBeDefined();
    expect(typeof lazyComp._init).toBe("function");
  });

  it("_payload starts in uninitialized state (-1)", () => {
    const lazyComp = lazy(() => Promise.resolve({ default: () => null }));
    expect(lazyComp._payload._status).toBe(-1);
  });

  it("calling _init triggers the loader and throws (pending promise)", () => {
    let resolveFn: (val: { default: () => null }) => void;
    const loader = () =>
      new Promise<{ default: () => null }>((resolve) => {
        resolveFn = resolve;
      });
    const lazyComp = lazy(loader);
    // First call should throw (the promise) since it's pending
    expect(() => lazyComp._init(lazyComp._payload)).toThrow();
    // Status should now be 0 (Pending) or 1 (Resolved) depending on timing
    expect(lazyComp._payload._status).toBeGreaterThanOrEqual(0);
    // Suppress unhandled promise rejection
    resolveFn!({ default: () => null });
  });

  it("resolves after promise resolves", async () => {
    const MyComp = () => null;
    const lazyComp = lazy(() => Promise.resolve({ default: MyComp }));

    // First call initializes (throws promise)
    try {
      lazyComp._init(lazyComp._payload);
    } catch (_e) {
      // expected to throw the pending promise
    }

    // Wait for microtasks
    await Promise.resolve();
    await Promise.resolve();

    // Now should be resolved (status = 1)
    expect(lazyComp._payload._status).toBe(1);
    const result = lazyComp._init(lazyComp._payload);
    expect(result).toBe(MyComp);
  });

  it("rejects on loader failure", async () => {
    const err = new Error("load failed");
    const lazyComp = lazy(() => Promise.reject(err));

    // First call initializes (throws promise)
    try {
      lazyComp._init(lazyComp._payload);
    } catch (_e) {
      // expected
    }

    await Promise.resolve();
    await Promise.resolve();

    // Status should be 2 (Rejected)
    expect(lazyComp._payload._status).toBe(2);
    expect(() => lazyComp._init(lazyComp._payload)).toThrow(err);
  });

  it("each lazy() call is independent", () => {
    const comp1 = lazy(() => Promise.resolve({ default: () => null }));
    const comp2 = lazy(() => Promise.resolve({ default: () => null }));
    expect(comp1._payload).not.toBe(comp2._payload);
  });
});

import { describe, expect, it } from "vitest";
import {
  createFiberFromElement,
  createFiberFromFragment,
  createFiberFromText,
  createFiberFromTypeAndProps,
  createHostRootFiber,
  createWorkInProgress,
  isSimpleFunctionComponent,
} from "../../../../src/core/react-engine/reconciler/ReactFiber.js";
import {
  ClassComponent,
  ContextConsumer,
  ContextProvider,
  ForwardRef,
  Fragment,
  FunctionComponent,
  HostComponent,
  HostRoot,
  HostText,
  LazyComponent,
  MemoComponent,
  SuspenseComponent,
} from "../../../../src/core/react-engine/reconciler/ReactWorkTags.js";
import { NoFlags } from "../../../../src/core/react-engine/reconciler/ReactFiberFlags.js";
import { NoLanes, SyncLane } from "../../../../src/core/react-engine/reconciler/ReactFiberLane.js";
import {
  REACT_CONSUMER_TYPE,
  REACT_CONTEXT_TYPE,
  REACT_FORWARD_REF_TYPE,
  REACT_FRAGMENT_TYPE,
  REACT_LAZY_TYPE,
  REACT_MEMO_TYPE,
  REACT_SUSPENSE_TYPE,
} from "../../../../src/core/react-engine/react/ReactSymbols.js";
import { Component } from "../../../../src/core/react-engine/react/ReactBaseClasses.js";

describe("ReactFiber", () => {
  describe("isSimpleFunctionComponent", () => {
    it("returns true for plain function component", () => {
      function MyComp() {
        return null;
      }
      expect(isSimpleFunctionComponent(MyComp)).toBe(true);
    });

    it("returns false for class components", () => {
      class MyClass extends Component {
        render() {
          return null;
        }
      }
      expect(isSimpleFunctionComponent(MyClass)).toBe(false);
    });

    it("returns false for non-function", () => {
      expect(isSimpleFunctionComponent("div")).toBe(false);
      expect(isSimpleFunctionComponent(null)).toBe(false);
      expect(isSimpleFunctionComponent({})).toBe(false);
    });

    it("returns false for function with defaultProps", () => {
      function WithDefaults() {
        return null;
      }
      (WithDefaults as unknown as Record<string, unknown>).defaultProps = {};
      expect(isSimpleFunctionComponent(WithDefaults)).toBe(false);
    });
  });

  describe("createHostRootFiber", () => {
    it("creates a fiber with HostRoot tag", () => {
      const fiber = createHostRootFiber();
      expect(fiber.tag).toBe(HostRoot);
    });

    it("has default initial values", () => {
      const fiber = createHostRootFiber();
      expect(fiber.key).toBeNull();
      expect(fiber.pendingProps).toBeNull();
      expect(fiber.flags).toBe(NoFlags);
      expect(fiber.lanes).toBe(NoLanes);
      expect(fiber.child).toBeNull();
      expect(fiber.return).toBeNull();
      expect(fiber.sibling).toBeNull();
      expect(fiber.alternate).toBeNull();
    });
  });

  describe("createFiberFromText", () => {
    it("creates a HostText fiber with content", () => {
      const fiber = createFiberFromText("hello", SyncLane);
      expect(fiber.tag).toBe(HostText);
      expect(fiber.pendingProps).toBe("hello");
      expect(fiber.lanes).toBe(SyncLane);
    });

    it("has null key for text nodes", () => {
      const fiber = createFiberFromText("world", NoLanes);
      expect(fiber.key).toBeNull();
    });
  });

  describe("createFiberFromFragment", () => {
    it("creates a Fragment fiber", () => {
      const children = [1, 2];
      const fiber = createFiberFromFragment(children, SyncLane, "mykey");
      expect(fiber.tag).toBe(Fragment);
      expect(fiber.pendingProps).toBe(children);
      expect(fiber.lanes).toBe(SyncLane);
      expect(fiber.key).toBe("mykey");
    });
  });

  describe("createFiberFromTypeAndProps", () => {
    it("creates FunctionComponent fiber for function type", () => {
      function Comp() {
        return null;
      }
      const fiber = createFiberFromTypeAndProps(Comp, null, {}, SyncLane);
      expect(fiber.tag).toBe(FunctionComponent);
      expect(fiber.type).toBe(Comp);
      expect(fiber.elementType).toBe(Comp);
    });

    it("creates ClassComponent fiber for class type", () => {
      class MyClass extends Component {
        render() {
          return null;
        }
      }
      const fiber = createFiberFromTypeAndProps(MyClass, null, {}, SyncLane);
      expect(fiber.tag).toBe(ClassComponent);
    });

    it("creates HostComponent fiber for string type", () => {
