  it("output validation fails for invalid JSON response", async () => {
    const outputSchema = z.object({ value: z.number() });
    const tool = baseProcedure
      .tool("output_invalid_tool", "Invalid output", { x: z.string() })
      .output(outputSchema)
      .handler(async () => ({
