describe("middleware", () => {
  it("creates a middleware with fn property", () => {
    const mw = middleware<Record<string, unknown>, { userId: string }>(async ({ ctx, next }) =>
      next({ ...ctx, userId: "user-123" }),
    );
    expect(typeof mw.fn).toBe("function");
  });

  it("middleware can be used in a procedure chain", async () => {
    const withUserId = middleware<Record<string, unknown>, { userId: string }>(async ({ ctx, next }) =>
      next({ ...ctx, userId: "user-123" }),
    );

    const t = createProcedure().use(withUserId);

    const tool = t
      .tool("user_tool", "Uses user id", { name: z.string() })
      .handler(async ({ input, ctx }) => ({
        content: [{ type: "text", text: `${input.name} by ${ctx.userId}` }],
      }));

    const result = await tool.handler({ name: "Alice" }, {});
    expect(result.content[0]!.text).toBe("Alice by user-123");
  });

  it("middleware receives input and context", async () => {
    const capturedParams: { input: unknown; ctx: unknown }[] = [];

    const captureMw = middleware<Record<string, unknown>, Record<string, unknown>>(async ({ input, ctx, next }) => {
      capturedParams.push({ input, ctx });
      return next(ctx);
    });

    const tool = createProcedure()
      .use(captureMw)
      .tool("capture_tool", "Captures params", { value: z.number() })
      .handler(async ({ input }) => ({
        content: [{ type: "text", text: String(input.value) }],
      }));

    await tool.handler({ value: 42 }, { existingKey: "hello" });
    expect(capturedParams).toHaveLength(1);
    expect(capturedParams[0]!.input).toEqual({ value: 42 });
    expect(capturedParams[0]!.ctx).toEqual({ existingKey: "hello" });
  });

  it("multiple middleware compose correctly", async () => {
    const steps: string[] = [];

    const mw1 = middleware<Record<string, unknown>, { step1: boolean }>(async ({ ctx, next }) => {
      steps.push("mw1-before");
      const result = await next({ ...ctx, step1: true });
      steps.push("mw1-after");
      return result;
    });

    const mw2 = middleware<{ step1: boolean }, { step1: boolean; step2: boolean }>(
      async ({ ctx, next }) => {
        steps.push("mw2-before");
        const result = await next({ ...ctx, step2: true });
        steps.push("mw2-after");
        return result;
      },
    );

    const tool = createProcedure()
      .use(mw1)
      .use(mw2)
      .tool("multi_mw_tool", "Multi middleware", { x: z.string() })
      .handler(async ({ ctx }) => {
        steps.push("handler");
        expect((ctx as { step1: boolean; step2: boolean }).step1).toBe(true);
        expect((ctx as { step1: boolean; step2: boolean }).step2).toBe(true);
        return { content: [{ type: "text", text: "done" }] };
      });

    await tool.handler({ x: "test" }, {});
    expect(steps).toEqual(["mw1-before", "mw2-before", "handler", "mw2-after", "mw1-after"]);
  });

  it("middleware can be short-circuit the chain", async () => {
    const authMw = middleware<Record<string, unknown>, { authorized: boolean }>(async () => {
      // Don't call next — return error immediately
      return {
        content: [{ type: "text", text: "Unauthorized" }],
        isError: true,
      };
    });

    const handlerCalled = { value: false };
    const tool = createProcedure()
      .use(authMw)
      .tool("auth_tool", "Auth required", { x: z.string() })
      .handler(async () => {
        handlerCalled.value = true;
        return { content: [{ type: "text", text: "secret" }] };
      });

    const result = await tool.handler({ x: "test" }, {});
    expect(result.isError).toBe(true);
    expect(result.content[0]!.text).toBe("Unauthorized");
    expect(handlerCalled.value).toBe(false);
  });

  it("handler receives initial ctx when no middleware", async () => {
    const tool = baseProcedure
      .tool("ctx_tool", "Gets ctx", { x: z.string() })
      .handler(async ({ ctx }) => ({
        content: [{ type: "text", text: JSON.stringify(ctx) }],
      }));

    const result = await tool.handler({ x: "test" }, { myKey: "myValue" });
    expect(result.content[0]!.text).toContain("myValue");
  });

  it("handler receives empty object ctx when ctx arg omitted", async () => {
    const tool = baseProcedure
      .tool("no_ctx_tool", "No ctx arg", { x: z.string() })
      .handler(async ({ ctx }) => ({
        content: [{ type: "text", text: JSON.stringify(ctx) }],
      }));

    const result = await tool.handler({ x: "test" });
    expect(result.content[0]!.text).toBe("{}");
  });
});

import { describe, it, expect } from "vitest";
import {
  generateBadgeToken,
  verifyBadgeToken,
  type BadgePayload,
} from "../../../src/core/shared-utils/core-logic/badge-token.js";

const SECRET = "test-secret-key";

function makePayload(overrides: Partial<BadgePayload> = {}): BadgePayload {
  return {
    sid: "session-abc123",
    topic: "typescript-basics",
    score: 95,
    ts: 1700000000000,
    ...overrides,
  };
}

describe("generateBadgeToken", () => {
  it("returns a string with exactly two dot-separated parts", () => {
    const token = generateBadgeToken(makePayload(), SECRET);
    const parts = token.split(".");
    expect(parts).toHaveLength(2);
    expect(parts[0]).toBeTruthy();
    expect(parts[1]).toBeTruthy();
  });

  it("encodes the payload as base64 in the first part", () => {
    const payload = makePayload();
    const token = generateBadgeToken(payload, SECRET);
    const payloadPart = token.split(".")[0]!;
    const decoded = JSON.parse(atob(payloadPart)) as BadgePayload;
    expect(decoded).toEqual(payload);
  });

  it("produces the same token for identical inputs (deterministic)", () => {
    const payload = makePayload();
    const token1 = generateBadgeToken(payload, SECRET);
    const token2 = generateBadgeToken(payload, SECRET);
    expect(token1).toBe(token2);
  });

  it("produces different tokens for different secrets", () => {
    const payload = makePayload();
    const token1 = generateBadgeToken(payload, "secret-a");
    const token2 = generateBadgeToken(payload, "secret-b");
    expect(token1).not.toBe(token2);
    // Payload part is the same, only signature differs
    expect(token1.split(".")[0]).toBe(token2.split(".")[0]);
    expect(token1.split(".")[1]).not.toBe(token2.split(".")[1]);
  });

  it("produces different tokens for different payloads", () => {
    const token1 = generateBadgeToken(makePayload({ score: 80 }), SECRET);
    const token2 = generateBadgeToken(makePayload({ score: 90 }), SECRET);
    expect(token1).not.toBe(token2);
  });

  it("handles payloads with score of 0", () => {
    const payload = makePayload({ score: 0 });
    const token = generateBadgeToken(payload, SECRET);
    expect(token.split(".")).toHaveLength(2);
  });
});

describe("verifyBadgeToken", () => {
  it("returns the original payload for a valid token", () => {
    const payload = makePayload();
    const token = generateBadgeToken(payload, SECRET);
    const result = verifyBadgeToken(token, SECRET);
    expect(result).toEqual(payload);
  });

  it("returns null for a token with wrong secret", () => {
    const token = generateBadgeToken(makePayload(), SECRET);
    const result = verifyBadgeToken(token, "wrong-secret");
    expect(result).toBeNull();
  });

  it("returns null for a tampered payload", () => {
    const payload = makePayload();
    const token = generateBadgeToken(payload, SECRET);
    // Modify the payload part but keep the original signature
    const tamperedPayload = btoa(JSON.stringify({ ...payload, score: 100 }));
    const sig = token.split(".")[1];
    const tamperedToken = `${tamperedPayload}.${sig}`;
    expect(verifyBadgeToken(tamperedToken, SECRET)).toBeNull();
  });

  it("returns null for a token with only one part (no dot)", () => {
    expect(verifyBadgeToken("nodotatall", SECRET)).toBeNull();
  });

  it("returns null for a token with more than two parts", () => {
    expect(verifyBadgeToken("part1.part2.part3", SECRET)).toBeNull();
  });

  it("returns null for an empty string", () => {
    expect(verifyBadgeToken("", SECRET)).toBeNull();
  });

  it("returns null for a token with invalid base64 payload", () => {
    expect(verifyBadgeToken("not-valid-base64!@#.signature", SECRET)).toBeNull();
  });

  it("returns null when payload part is empty", () => {
    expect(verifyBadgeToken(".signature", SECRET)).toBeNull();
  });

  it("returns null when signature part is empty", () => {
    const payload = makePayload();
    const token = generateBadgeToken(payload, SECRET);
    const payloadPart = token.split(".")[0];
    expect(verifyBadgeToken(`${payloadPart}.`, SECRET)).toBeNull();
  });

  it("round-trips all payload fields correctly", () => {
    const payload: BadgePayload = {
      sid: "uuid-special-chars",
      topic: "advanced-typescript/generics",
      score: 42,
      ts: Date.now(),
    };
    const token = generateBadgeToken(payload, SECRET);
    const verified = verifyBadgeToken(token, SECRET);
    expect(verified).not.toBeNull();
    expect(verified!.sid).toBe(payload.sid);
    expect(verified!.topic).toBe(payload.topic);
    expect(verified!.score).toBe(payload.score);
    expect(verified!.ts).toBe(payload.ts);
  });
});

