  describe("Versioning", () => {
    it("registers multiple versions and resolves latest", () => {
      const server = createMockMcpServer();
      const registry = new ToolRegistry(server, "user-1");

      registry.register({
        name: "v_tool",
        description: "v1",
        category: "c",
        tier: "free",
        version: "1.0.0",
        handler: () => ({ content: [{ type: "text", text: "v1" }] }),
      });

      registry.register({
        name: "v_tool",
        description: "v2",
        category: "c",
        tier: "free",
        version: "2.0.0",
        handler: () => ({ content: [{ type: "text", text: "v2" }] }),
      });

      // The latest in the main map should be v2
      const defs = registry.getToolDefinitions();
      expect(defs).toHaveLength(1);
      expect(defs[0].version).toBe("2.0.0");

      // Auto-deprecation: v1 should be marked deprecated
      const v1Def = registry.getToolByVersion("v_tool", "1.0.0");
      expect(v1Def?.stability).toBe("deprecated");
    });

    it("does not overwrite latest if older version is registered later", () => {
      const server = createMockMcpServer();
      const registry = new ToolRegistry(server, "user-1");

      registry.register({
        name: "v_tool",
        description: "v2",
        category: "c",
        tier: "free",
        version: "2.0.0",
        handler: () => ({ content: [{ type: "text", text: "v2" }] }),
      });

      registry.register({
        name: "v_tool",
        description: "v1",
        category: "c",
        tier: "free",
        version: "1.0.0",
        handler: () => ({ content: [{ type: "text", text: "v1" }] }),
      });

      // The latest in the main map should still be v2
      const defs = registry.getToolDefinitions();
      expect(defs).toHaveLength(1);
      expect(defs[0].version).toBe("2.0.0");

      // The older one can still be accessed via version
      const v1Def = registry.getToolByVersion("v_tool", "1.0.0");
      expect(v1Def?.version).toBe("1.0.0");
    });

    it("listVersions returns sorted list of versions", () => {
      const server = createMockMcpServer();
      const registry = new ToolRegistry(server, "user-1");

      registry.register({
        name: "v_tool",
        description: "v1",
        category: "c",
        tier: "free",
        version: "1.0.0",
        handler: () => ({ content: [] }),
      });
      registry.register({
        name: "v_tool",
        description: "v2",
        category: "c",
        tier: "free",
        version: "2.0.0",
        handler: () => ({ content: [] }),
      });
      registry.register({
        name: "v_tool",
        description: "v1.5",
        category: "c",
        tier: "free",
        version: "1.5.0",
        handler: () => ({ content: [] }),
      });

      const versions = registry.listVersions("v_tool");
      expect(versions).toHaveLength(3);
      expect(versions[0].version).toBe("2.0.0");
      expect(versions[1].version).toBe("1.5.0");
      expect(versions[2].version).toBe("1.0.0");
      expect(versions[2].stability).toBe("deprecated");
    });

    it("can call specific version directly", async () => {
      const server = createMockMcpServer();
      const registry = new ToolRegistry(server, "user-1");

      registry.register({
        name: "v_tool",
        description: "v1",
        category: "c",
        tier: "free",
        version: "1.0.0",
        alwaysEnabled: true,
        handler: () => ({ content: [{ type: "text" as const, text: "v1 response" }] }),
      });

      registry.register({
        name: "v_tool",
        description: "v2",
        category: "c",
        tier: "free",
        version: "2.0.0",
        alwaysEnabled: true,
        handler: () => ({ content: [{ type: "text" as const, text: "v2 response" }] }),
      });

      registry.enableAll();

      const r2 = await registry.callToolDirect("v_tool", {});
      expect(r2.content[0].text).toBe("v2 response");

      const r1 = await registry.callToolDirect("v_tool", {}, undefined, "1.0.0");
      expect(r1.content[0].text).toBe("v1 response");
    });
  });
});

import { describe, expect, it } from "vitest";
import {
  optimizeSchema,
  shortenDescription,
  measureTokenSavings,
  getSchemaTokenReport,
  injectExamplesIntoSchema,
} from "../../../src/edge-api/spike-land/core-logic/mcp/schema-optimizer";

describe("optimizeSchema", () => {
  it("returns a copy without mutating the original", () => {
    const schema = { description: "A schema" };
    const result = optimizeSchema(schema);
    expect(result).toEqual({ description: "Schema" });
    expect(result).not.toBe(schema);
  });

  it("strips descriptions that exactly match the property name", () => {
    const schema = {
      type: "object",
      properties: {
        name: { type: "string", description: "name" },
        age: { type: "number", description: "User age in years" },
      },
    };

    const result = optimizeSchema(schema) as Record<string, unknown>;
    const props = result.properties as Record<string, Record<string, unknown>>;
    expect(props.name).not.toHaveProperty("description");
    expect(props.age!.description).toBe("User age in years");
  });

  it("strips 'the <name>' descriptions", () => {
    const schema = {
      type: "object",
      properties: {
        query: { type: "string", description: "The query" },
      },
    };

    const result = optimizeSchema(schema) as Record<string, unknown>;
    const props = result.properties as Record<string, Record<string, unknown>>;
    expect(props.query).not.toHaveProperty("description");
  });

  it("strips 'a <name>' descriptions", () => {
    const schema = {
      type: "object",
      properties: {
        file: { type: "string", description: "A file" },
      },
    };

    const result = optimizeSchema(schema) as Record<string, unknown>;
    const props = result.properties as Record<string, Record<string, unknown>>;
    expect(props.file).not.toHaveProperty("description");
  });

  it("handles underscore/hyphen property names", () => {
    const schema = {
      type: "object",
      properties: {
        file_path: { type: "string", description: "file path" },
        "max-count": { type: "number", description: "The max count" },
      },
    };

    const result = optimizeSchema(schema) as Record<string, unknown>;
    const props = result.properties as Record<string, Record<string, unknown>>;
    expect(props.file_path).not.toHaveProperty("description");
    expect(props["max-count"]).not.toHaveProperty("description");
  });

  it("strips 'the <words> of the <name>' descriptions", () => {
    const schema = {
      type: "object",
      properties: {
        image_id: { type: "string", description: "The ID of the image_id" },
        user_id: { type: "string", description: "ID for user_id" },
      },
