    addTransition(id, {
      source: "a",
      target: "done",
      event: "FINISH",
      actions: [],
      internal: false,
    });
    const issues = validateMachine(id);
    expect(issues.some((i) => i.stateId === "done" && i.message.includes("dead-end"))).toBe(false);
  });
});

