    );
    expect(result.success).toBe(false);
    expect(result.error).toBe("Message not found in context");
  });

  it("processes E2E_TEST_ECHO keyword and returns success", async () => {
    const context = {
      ...baseContext,
      chatHistory: [
        {
          id: "msg1",
          role: "USER" as const,
          content: "E2E_TEST_ECHO:ping",
          createdAt: "2024-01-01",
          attachments: [],
        },
      ],
