  });

  it("runs poll once and exits 0 with --once flag", async () => {
    vi.mocked(agentModule.poll).mockResolvedValue(2);
    const spy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);
    await getAction("poll")({ once: true, stats: false, interval: "5000" });
    expect(spy).toHaveBeenCalledWith(0);
    expect(agentModule.poll).toHaveBeenCalled();
    spy.mockRestore();
  });

  it("exits with code 1 when getRedisConfig throws", async () => {
    vi.mocked(redisModule.getRedisConfig).mockImplementationOnce(() => {
      throw new Error("Redis config error");
    });
    const spy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);
    await getAction("poll")({ stats: false, once: false, interval: "5000" });
    expect(spy).toHaveBeenCalledWith(1);
    spy.mockRestore();
  });

  it("uses default interval of 2000 when interval is not a valid number", async () => {
    vi.mocked(agentModule.poll).mockResolvedValue(0);
    vi.useFakeTimers();
    const sigintHandlers: (() => void)[] = [];
    const onSpy = vi.spyOn(process, "on").mockImplementation((event, fn) => {
      if (event === "SIGINT") sigintHandlers.push(fn as () => void);
      return process;
    });
    const exitSpy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);

    // Start poll action with invalid interval
    getAction("poll")({ once: false, stats: false, interval: "not-a-number" });

    // Let the poll loop run once
    await vi.advanceTimersByTimeAsync(2001);

    if (sigintHandlers.length > 0) sigintHandlers[0]!();

    expect(agentModule.poll).toHaveBeenCalled();

    vi.useRealTimers();
    onSpy.mockRestore();
    exitSpy.mockRestore();
  });

  it("runs continuous polling loop", async () => {
    vi.useFakeTimers();
    vi.mocked(agentModule.poll).mockResolvedValue(0);
    const sigintHandlers: (() => void)[] = [];
    const onSpy = vi.spyOn(process, "on").mockImplementation((event, fn) => {
      if (event === "SIGINT") sigintHandlers.push(fn as () => void);
      return process;
    });
    const exitSpy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);

    getAction("poll")({ once: false, stats: false, interval: "100" });

    // Let one tick of the poll loop run
    await vi.advanceTimersByTimeAsync(200);

    // Trigger SIGINT to stop the loop
    if (sigintHandlers.length > 0) sigintHandlers[0]!();

    vi.useRealTimers();
    onSpy.mockRestore();
    exitSpy.mockRestore();

    expect(agentModule.poll).toHaveBeenCalled();
  });

  it("logs poll error when poll throws in continuous loop", async () => {
    vi.useFakeTimers();
    vi.mocked(agentModule.poll).mockRejectedValue(new Error("poll error"));
    const errSpy = vi.spyOn(console, "error").mockImplementation(() => {});
    const sigintHandlers: (() => void)[] = [];
    const onSpy = vi.spyOn(process, "on").mockImplementation((event, fn) => {
      if (event === "SIGINT") sigintHandlers.push(fn as () => void);
      return process;
    });
    const exitSpy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);

    getAction("poll")({ once: false, stats: false, interval: "100" });
    // Let the poll loop run (error will be caught and logged)
    await vi.advanceTimersByTimeAsync(200);

    if (sigintHandlers.length > 0) sigintHandlers[0]!();

    vi.useRealTimers();
    onSpy.mockRestore();
    exitSpy.mockRestore();
    errSpy.mockRestore();

    expect(agentModule.poll).toHaveBeenCalled();
  });

  it("SIGTERM handler exits with 0 in continuous poll loop", async () => {
    vi.useFakeTimers();
    vi.mocked(agentModule.poll).mockResolvedValue(0);
    const sigtermHandlers: (() => void)[] = [];
    const onSpy = vi.spyOn(process, "on").mockImplementation((event, fn) => {
      if (event === "SIGTERM") sigtermHandlers.push(fn as () => void);
      return process;
    });
    const exitSpy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);

    getAction("poll")({ once: false, stats: false, interval: "100" });
    await vi.advanceTimersByTimeAsync(50);

    if (sigtermHandlers.length > 0) sigtermHandlers[0]!();

    expect(exitSpy).toHaveBeenCalledWith(0);

    vi.useRealTimers();
    onSpy.mockRestore();
    exitSpy.mockRestore();
  });
});

describe("CLI dev command", () => {
  beforeEach(() => {
    vi.spyOn(console, "log").mockImplementation(() => {});
    vi.spyOn(console, "error").mockImplementation(() => {});
  });
  afterEach(() => vi.restoreAllMocks());

  it("exits with code 1 when no codespace provided", async () => {
    const spy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);
    await getAction("dev")({ codespace: [], debounce: "100" });
    expect(spy).toHaveBeenCalledWith(1);
    spy.mockRestore();
  });

  it("exits with code 1 when startDevMode fails", async () => {
    vi.mocked(watcherModule.startDevMode).mockRejectedValue(new Error("watcher failed"));
    const spy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);
    await getAction("dev")({ codespace: ["my-space"], debounce: "100" });
    expect(spy).toHaveBeenCalledWith(1);
    spy.mockRestore();
  });

  it("uses default debounce of 300 when debounce value is not a valid number", async () => {
    const stopFn = vi.fn().mockResolvedValue(undefined);
    vi.mocked(watcherModule.startDevMode).mockResolvedValue({ stop: stopFn } as never);
    const onSpy = vi.spyOn(process, "on").mockImplementation(() => process);
    vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);

    // Don't await - action hangs; just check startDevMode gets called with 300 debounce
    getAction("dev")({ codespace: ["my-space"], debounce: "not-a-number" });

    await new Promise((r) => setTimeout(r, 10));

    expect(watcherModule.startDevMode).toHaveBeenCalledWith(
      ["my-space"],
      expect.objectContaining({ debounceMs: 300 }),
    );
    onSpy.mockRestore();
    vi.restoreAllMocks();
  });

  it("SIGINT handler calls stop and exits with 0", async () => {
    const stopFn = vi.fn().mockResolvedValue(undefined);
    vi.mocked(watcherModule.startDevMode).mockResolvedValue({ stop: stopFn } as never);

    const sigintHandlers: Array<() => void> = [];
    const onSpy = vi.spyOn(process, "on").mockImplementation((event, fn) => {
      if (event === "SIGINT") sigintHandlers.push(fn as () => void);
      return process;
    });
    const exitSpy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);

    // Don't await - action hangs in `await new Promise(() => {})` until SIGINT
    getAction("dev")({ codespace: ["my-space"], debounce: "100" });

    // Wait for startDevMode + process.on setup
    await new Promise((r) => setTimeout(r, 10));

    // Trigger SIGINT
    if (sigintHandlers.length > 0) await sigintHandlers[0]!();

    expect(stopFn).toHaveBeenCalled();
    expect(exitSpy).toHaveBeenCalledWith(0);

    onSpy.mockRestore();
    exitSpy.mockRestore();
  });

  it("SIGTERM handler calls stop and exits with 0", async () => {
    const stopFn = vi.fn().mockResolvedValue(undefined);
    vi.mocked(watcherModule.startDevMode).mockResolvedValue({ stop: stopFn } as never);

    const sigtermHandlers: Array<() => void> = [];
    const onSpy = vi.spyOn(process, "on").mockImplementation((event, fn) => {
      if (event === "SIGTERM") sigtermHandlers.push(fn as () => void);
      return process;
    });
    const exitSpy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);

    getAction("dev")({ codespace: ["my-space"], debounce: "100" });
    await new Promise((r) => setTimeout(r, 10));

    if (sigtermHandlers.length > 0) await sigtermHandlers[0]!();

    expect(stopFn).toHaveBeenCalled();
    expect(exitSpy).toHaveBeenCalledWith(0);

    onSpy.mockRestore();
    exitSpy.mockRestore();
  });

  it("onSync callback logs synced message", async () => {
    let capturedOnSync: ((id: string) => void) | undefined;
    const stopFn = vi.fn().mockResolvedValue(undefined);
    vi.mocked(watcherModule.startDevMode).mockImplementation(async (_ids, opts) => {
      capturedOnSync = opts?.onSync;
      return { stop: stopFn } as never;
    });

    const logSpy = vi.spyOn(console, "log").mockImplementation(() => {});
    const onSpy = vi.spyOn(process, "on").mockImplementation(() => process);
    const exitSpy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);

    // Start the action - it will hang at `await new Promise(() => {})`; do NOT await
    getAction("dev")({ codespace: ["my-space"], debounce: "100" });

    // Wait for startDevMode to resolve so capturedOnSync is set
    await new Promise((r) => setTimeout(r, 10));

    // Invoke the onSync callback directly
    expect(capturedOnSync).toBeDefined();
    capturedOnSync!("my-space");

    expect(logSpy).toHaveBeenCalledWith(expect.stringContaining("my-space"));

    onSpy.mockRestore();
    exitSpy.mockRestore();
    logSpy.mockRestore();
  });
});

describe("CLI claude command", () => {
  beforeEach(() => {
    vi.spyOn(console, "log").mockImplementation(() => {});
    vi.spyOn(console, "error").mockImplementation(() => {});
    vi.mocked(mkdir).mockResolvedValue(undefined);
    vi.mocked(writeFile).mockResolvedValue(undefined);
    vi.mocked(spawn).mockClear();
  });
  afterEach(() => vi.restoreAllMocks());

  it("spawns claude with mcp config and system prompt when codespace provided", async () => {
    const mockProc = new EventEmitter();
    vi.mocked(spawn).mockReturnValue(mockProc as unknown as ChildProcess);
    const exitSpy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);

    // The claude action is async but doesn't await the spawn events.
    // We need to wait for process.exit to be called via the close event.
    const exitCalled = new Promise<void>((resolve) => {
      exitSpy.mockImplementation((() => resolve()) as () => never);
    });

    getAction("claude")({ codespace: "my-space", prompt: "build it" }, { args: [] });
    // Give the action time to set up spawn listeners, then emit close
    await new Promise((r) => process.nextTick(r));
    mockProc.emit("close", 0);
    await exitCalled;

    expect(spawn).toHaveBeenCalledWith(
      "claude",
      expect.arrayContaining(["--mcp-config"]),
      expect.objectContaining({ stdio: ["pipe", "inherit", "inherit"] }),
    );
    exitSpy.mockRestore();
  });

  it("spawns claude without system prompt when no codespace", async () => {
    const mockProc = new EventEmitter();
    vi.mocked(spawn).mockReturnValue(mockProc as unknown as ChildProcess);
    const exitSpy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);

    const exitCalled = new Promise<void>((resolve) => {
      exitSpy.mockImplementation((() => resolve()) as () => never);
    });

    getAction("claude")({ prompt: "just a prompt" }, { args: ["--verbose"] });
    await new Promise((r) => process.nextTick(r));
    mockProc.emit("close", 0);
    await exitCalled;

    // mock.calls[0] is for this test since we cleared spawn in beforeEach
    const spawnArgs = vi.mocked(spawn).mock.calls[0]![1] as string[];
    expect(spawnArgs).not.toContain("--system-prompt");
    exitSpy.mockRestore();
  });

  it("exits with code 1 when spawn emits error", async () => {
    const mockProc = new EventEmitter();
    vi.mocked(spawn).mockReturnValue(mockProc as unknown as ChildProcess);
    const exitSpy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);

    const exitCalled = new Promise<void>((resolve) => {
      exitSpy.mockImplementation((() => resolve()) as () => never);
    });

    getAction("claude")({ codespace: "my-space" }, { args: [] });
    await new Promise((r) => process.nextTick(r));
    mockProc.emit("error", new Error("spawn failed"));
    await exitCalled;

    expect(exitSpy).toHaveBeenCalledWith(1);
    exitSpy.mockRestore();
  });

  it("exits with code 1 when mkdir fails", async () => {
    vi.mocked(mkdir).mockRejectedValue(new Error("mkdir failed"));
    const exitSpy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);
    await getAction("claude")({ codespace: "my-space" }, { args: [] });
    expect(exitSpy).toHaveBeenCalledWith(1);
    exitSpy.mockRestore();
  });

  it("uses empty array when command.args is null/falsy", async () => {
    const mockProc = new EventEmitter();
    vi.mocked(spawn).mockReturnValue(mockProc as unknown as ChildProcess);
    const exitSpy = vi.spyOn(process, "exit").mockImplementation((() => {}) as () => never);

    const exitCalled = new Promise<void>((resolve) => {
      exitSpy.mockImplementation((() => resolve()) as () => never);
    });

    // Pass command with null args to exercise the `|| []` fallback
    getAction("claude")({ prompt: "hi" }, { args: null });
    await new Promise((r) => process.nextTick(r));
    mockProc.emit("close", 0);
    await exitCalled;

    expect(spawn).toHaveBeenCalledWith("claude", expect.any(Array), expect.any(Object));
    exitSpy.mockRestore();
  });
});

import chokidar, { type FSWatcher } from "chokidar";
import { existsSync, mkdirSync } from "fs";
import { readFile, writeFile } from "fs/promises";
import path from "path";
import { beforeEach, describe, expect, it, vi } from "vitest";
import { pullCode, pushCode, withRetry } from "../../../src/cli/docker-dev/core-logic/sync.js";
import * as watcher from "../../../src/cli/docker-dev/lazy-imports/watcher.js";

// Mock dependencies
vi.mock("fs");
vi.mock("fs/promises");
vi.mock("chokidar");
vi.mock("../../../src/cli/docker-dev/core-logic/sync.js");

describe("Watcher Module", () => {
  const mockWatcher: Pick<FSWatcher, "on" | "close"> = {
    on: vi.fn(),
    close: vi.fn(),
  };

  beforeEach(() => {
    vi.resetAllMocks();
    vi.mocked(chokidar.watch).mockReturnValue(mockWatcher as FSWatcher);
    vi.mocked(withRetry).mockImplementation(async (fn: () => Promise<unknown>) => fn());
    vi.mocked(mockWatcher.close).mockResolvedValue(undefined as never);
  });

  describe("getLiveDir", () => {
    it("should return live directory path", () => {
      const dir = watcher.getLiveDir();
      expect(dir).toBe(path.join(process.cwd(), "live"));
    });
  });

  describe("getLocalPath", () => {
    it("should return local file path", () => {
      const filePath = watcher.getLocalPath("test-code");
      expect(filePath).toBe(path.join(process.cwd(), "live", "test-code.tsx"));
    });

    it("should sanitize codespace id", () => {
      const filePath = watcher.getLocalPath("test/code");
      expect(filePath).toBe(path.join(process.cwd(), "live", "test-code.tsx"));
    });
  });

  describe("ensureLiveDir", () => {
    it("should create directory if it does not exist", () => {
      vi.mocked(existsSync).mockReturnValue(false);
      watcher.ensureLiveDir();
      expect(mkdirSync).toHaveBeenCalledWith(expect.stringContaining("live"), {
        recursive: true,
      });
    });

    it("should not create directory if it exists", () => {
      vi.mocked(existsSync).mockReturnValue(true);
      watcher.ensureLiveDir();
      expect(mkdirSync).not.toHaveBeenCalled();
    });
  });

  describe("downloadToLocal", () => {
    it("should download code and save to file", async () => {
      vi.mocked(pullCode).mockResolvedValue("code content");
      vi.mocked(existsSync).mockReturnValue(true);

      const result = await watcher.downloadToLocal("code1");

      expect(result).toContain("code1.tsx");
      expect(pullCode).toHaveBeenCalledWith("code1");
      expect(writeFile).toHaveBeenCalledWith(
        expect.stringContaining("code1.tsx"),
        "code content",
        "utf-8",
      );
      expect(writeFile).toHaveBeenCalledWith(
        expect.stringContaining("code1.meta.json"),
        expect.any(String),
        "utf-8",
      );
    });

    it("should propagate pullCode errors", async () => {
      vi.mocked(pullCode).mockRejectedValue(new Error("fetch failed"));
      vi.mocked(existsSync).mockReturnValue(true);

      await expect(watcher.downloadToLocal("code1")).rejects.toThrow("fetch failed");
    });

    it("should write valid JSON metadata with correct fields", async () => {
      vi.mocked(pullCode).mockResolvedValue("hello code");
      vi.mocked(existsSync).mockReturnValue(true);

      await watcher.downloadToLocal("space-x");

      const metaCall = vi
        .mocked(writeFile)
        .mock.calls.find(([p]) => String(p).includes(".meta.json"));
      expect(metaCall).toBeDefined();
      const meta = JSON.parse(String(metaCall![1]));
      expect(meta.codespaceId).toBe("space-x");
      expect(meta.originalLength).toBe(10);
      expect(meta.downloadedAt).toBeTruthy();
    });
  });

  describe("watchCodespace", () => {
    it("should start watching file", () => {
      const w = watcher.watchCodespace("code1");

      expect(w.codespaceId).toBe("code1");
      expect(w.watcher).toBe(mockWatcher);
      expect(mockWatcher.on).toHaveBeenCalledWith("change", expect.any(Function));
      expect(mockWatcher.on).toHaveBeenCalledWith("error", expect.any(Function));
    });

    it("should sync changes when file changes", async () => {
      vi.useFakeTimers();
      watcher.watchCodespace("code1", { debounceMs: 100 });

      const changeHandler = vi
        .mocked(mockWatcher.on)
        .mock.calls.find((call) => call[0] === "change")![1];

      vi.mocked(readFile).mockResolvedValue("new code");
      changeHandler();
      await vi.advanceTimersByTimeAsync(100);

      expect(readFile).toHaveBeenCalled();
      expect(pushCode).toHaveBeenCalledWith("code1", "new code");
      vi.useRealTimers();
    });

    it("should call onSync callback after successful sync", async () => {
      vi.useFakeTimers();
      const onSync = vi.fn();
      watcher.watchCodespace("code1", { debounceMs: 50, onSync });

      const changeHandler = vi
        .mocked(mockWatcher.on)
        .mock.calls.find((call) => call[0] === "change")![1];

      vi.mocked(readFile).mockResolvedValue("synced code");
      vi.mocked(pushCode).mockResolvedValue({} as never);
      changeHandler();
      await vi.advanceTimersByTimeAsync(50);

      expect(onSync).toHaveBeenCalledWith("code1");
      vi.useRealTimers();
    });

    it("should call onError callback when sync fails", async () => {
      vi.useFakeTimers();
      const onError = vi.fn();
      watcher.watchCodespace("code1", { debounceMs: 50, onError });

      const changeHandler = vi
        .mocked(mockWatcher.on)
        .mock.calls.find((call) => call[0] === "change")![1];

      vi.mocked(readFile).mockResolvedValue("code");
      vi.mocked(withRetry).mockRejectedValue(new Error("push failed"));
      changeHandler();
      await vi.advanceTimersByTimeAsync(50);

      expect(onError).toHaveBeenCalledWith("code1", expect.any(Error));
      vi.useRealTimers();
    });

    it("should handle non-Error objects thrown during sync", async () => {
      vi.useFakeTimers();
      const onError = vi.fn();
      watcher.watchCodespace("code1", { debounceMs: 50, onError });

      const changeHandler = vi
        .mocked(mockWatcher.on)
        .mock.calls.find((call) => call[0] === "change")![1];

      vi.mocked(readFile).mockResolvedValue("code");
      vi.mocked(withRetry).mockRejectedValue("string error");
      changeHandler();
      await vi.advanceTimersByTimeAsync(50);

      expect(onError).toHaveBeenCalledWith(
        "code1",
        expect.objectContaining({ message: "string error" }),
      );
      vi.useRealTimers();
    });

    it("should debounce multiple rapid changes", async () => {
      vi.useFakeTimers();
      watcher.watchCodespace("code1", { debounceMs: 100 });

      const changeHandler = vi
        .mocked(mockWatcher.on)
        .mock.calls.find((call) => call[0] === "change")![1];

      vi.mocked(readFile).mockResolvedValue("code");
      vi.mocked(pushCode).mockResolvedValue({} as never);

      // Fire three times rapidly — debounce should collapse to one sync
      changeHandler();
      await vi.advanceTimersByTimeAsync(50);
      changeHandler();
      await vi.advanceTimersByTimeAsync(50);
      changeHandler();
      await vi.advanceTimersByTimeAsync(100);

      expect(pushCode).toHaveBeenCalledTimes(1);
      vi.useRealTimers();
    });

    it("should call onError from watcher error event", () => {
      const onError = vi.fn();
      watcher.watchCodespace("code1", { onError });

      const errorHandler = vi
        .mocked(mockWatcher.on)
        .mock.calls.find((call) => call[0] === "error")![1];

      errorHandler(new Error("fs error"));
      expect(onError).toHaveBeenCalledWith("code1", expect.any(Error));
    });

    it("should wrap non-Error in watcher error event", () => {
      const onError = vi.fn();
      watcher.watchCodespace("code1", { onError });

      const errorHandler = vi
        .mocked(mockWatcher.on)
        .mock.calls.find((call) => call[0] === "error")![1];

      errorHandler("plain string error");
      expect(onError).toHaveBeenCalledWith(
        "code1",
        expect.objectContaining({ message: "plain string error" }),
      );
    });

    it("stop() closes watcher and clears pending debounce timer", async () => {
      vi.useFakeTimers();
      const w = watcher.watchCodespace("code1", { debounceMs: 200 });

      const changeHandler = vi
        .mocked(mockWatcher.on)
        .mock.calls.find((call) => call[0] === "change")![1];

      vi.mocked(readFile).mockResolvedValue("code");
      changeHandler();

      // Stop before timer fires
      await w.stop();

      // Advance past debounce — push should NOT be called
      await vi.advanceTimersByTimeAsync(200);

      expect(mockWatcher.close).toHaveBeenCalled();
      expect(pushCode).not.toHaveBeenCalled();
      vi.useRealTimers();
    });

    it("stop() works even when no debounce timer is pending", async () => {
      const w = watcher.watchCodespace("code1");
      await w.stop();
      expect(mockWatcher.close).toHaveBeenCalled();
    });
  });

  describe("startDevMode", () => {
    it("should download all codespaces and return watchers", async () => {
      vi.mocked(pullCode).mockResolvedValue("some code");
      vi.mocked(existsSync).mockReturnValue(true);

      const result = await watcher.startDevMode(["code1", "code2"]);

      expect(result.watchers).toHaveLength(2);
      expect(pullCode).toHaveBeenCalledTimes(2);
      expect(pullCode).toHaveBeenCalledWith("code1");
      expect(pullCode).toHaveBeenCalledWith("code2");
    });

    it("stop() stops all watchers", async () => {
      vi.mocked(pullCode).mockResolvedValue("code");
      vi.mocked(existsSync).mockReturnValue(true);

      const result = await watcher.startDevMode(["code1", "code2"]);
      await result.stop();

      expect(mockWatcher.close).toHaveBeenCalledTimes(2);
    });

    it("propagates download error when a codespace fails", async () => {
      vi.mocked(pullCode).mockRejectedValue(new Error("network error"));
      vi.mocked(existsSync).mockReturnValue(true);

      await expect(watcher.startDevMode(["bad-code"])).rejects.toThrow("network error");
    });

    it("should handle empty codespace list", async () => {
      const result = await watcher.startDevMode([]);
      expect(result.watchers).toHaveLength(0);
      await result.stop();
    });
  });
});
